import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Auto Pitchfork — identifies three pivot points and draws Andrew's Pitchfork. */
export function autoPitchfork(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const lookback = (params["lookback"] as number | undefined) ?? 50;
  const len = data.length;

  const median = fillNaN(len);
  const upper = fillNaN(len);
  const lower = fillNaN(len);

  if (len < lookback || len < 10) {
    const timestamps = extractTimestamps(data);
    return buildOutput("auto-pitchfork", timestamps, [median, upper, lower]);
  }

  const findPivotHigh = (start: number, end: number): number => {
    let maxIdx = start;
    for (let i = start + 1; i <= end; i++) {
      if (data[i]!.high > data[maxIdx]!.high) maxIdx = i;
    }
    return maxIdx;
  };

  const findPivotLow = (start: number, end: number): number => {
    let minIdx = start;
    for (let i = start + 1; i <= end; i++) {
      if (data[i]!.low < data[minIdx]!.low) minIdx = i;
    }
    return minIdx;
  };

  const end = len - 1;
  const start = Math.max(0, end - lookback);
  const mid = Math.floor((start + end) / 2);

  const p0Idx = findPivotLow(start, mid);
  const p1Idx = findPivotHigh(mid, end);
  const p2Idx = findPivotLow(p1Idx, end);

  if (p0Idx >= p1Idx || p1Idx >= p2Idx) {
    const timestamps = extractTimestamps(data);
    return buildOutput("auto-pitchfork", timestamps, [median, upper, lower]);
  }

  const p0Price = data[p0Idx]!.low;
  const p1Price = data[p1Idx]!.high;
  const p2Price = data[p2Idx]!.low;

  const medianStart = (p1Price + p2Price) / 2;
  const medianSlope = (medianStart - p0Price) / (((p1Idx + p2Idx) / 2) - p0Idx);
  const channelWidth = Math.abs(p1Price - p2Price) / 2;

  for (let i = p0Idx; i < len; i++) {
    const dist = i - p0Idx;
    median[i] = p0Price + medianSlope * dist;
    upper[i] = median[i]! + channelWidth;
    lower[i] = median[i]! - channelWidth;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("auto-pitchfork", timestamps, [median, upper, lower]);
}
