import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, smaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Moving Average Envelopes — fixed percentage bands around SMA. */
export function envelopes(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const percent = (params["percent"] as number | undefined) ?? 2.5;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const middle = smaArray(src, period);
  const len = src.length;

  const upper = fillNaN(len);
  const lower = fillNaN(len);
  const mult = percent / 100;

  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(middle[i]!)) {
      upper[i] = middle[i]! * (1 + mult);
      lower[i] = middle[i]! * (1 - mult);
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("envelopes", timestamps, [upper, middle, lower]);
}
