import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Volume Weighted Moving Average. */
export function vwma(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = data.length;
  const result = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("vwma", timestamps, [result]);
  }

  let sumPV = 0;
  let sumV = 0;

  for (let i = 0; i < period; i++) {
    sumPV += src[i]! * data[i]!.volume;
    sumV += data[i]!.volume;
  }
  result[period - 1] = sumV === 0 ? src[period - 1]! : sumPV / sumV;

  for (let i = period; i < len; i++) {
    sumPV += src[i]! * data[i]!.volume - src[i - period]! * data[i - period]!.volume;
    sumV += data[i]!.volume - data[i - period]!.volume;
    result[i] = sumV === 0 ? src[i]! : sumPV / sumV;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vwma", timestamps, [result]);
}
