import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, smaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Detrended Price Oscillator — removes trend from price to identify cycles. */
export function dpo(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  const sma = smaArray(src, period);
  const shift = Math.floor(period / 2) + 1;

  for (let i = shift; i < len; i++) {
    if (!Number.isNaN(sma[i]!)) {
      result[i - shift] = src[i - shift]! - sma[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("dpo", timestamps, [result]);
}
