import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** 52-Week High/Low — rolling 52-week (or N-bar) highest high and lowest low. */
export function fiftyTwoWeekHL(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 252;
  const len = data.length;

  const highLine = fillNaN(len);
  const lowLine = fillNaN(len);

  for (let i = 0; i < len; i++) {
    const start = Math.max(0, i - period + 1);
    let hh = -Infinity;
    let ll = Infinity;
    for (let j = start; j <= i; j++) {
      if (data[j]!.high > hh) hh = data[j]!.high;
      if (data[j]!.low < ll) ll = data[j]!.low;
    }
    highLine[i] = hh;
    lowLine[i] = ll;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("fifty-two-week-hl", timestamps, [highLine, lowLine]);
}
