import type { OHLCV } from './market-data';

/** Indicator parameter type definitions. */
export enum IndicatorParamType {
  Integer = "integer",
  Float = "float",
  String = "string",
  Boolean = "boolean",
  Color = "color",
  Source = "source",
}

/** Single indicator parameter definition. */
export interface IndicatorParam {
  /** Parameter identifier (used as key in params object). */
  key: string;
  /** Display label for the parameter. */
  label: string;
  /** Parameter type. */
  type: IndicatorParamType;
  /** Default value. */
  defaultValue: number | string | boolean;
  /** Minimum value (for numeric types). */
  min?: number;
  /** Maximum value (for numeric types). */
  max?: number;
  /** Step value (for numeric types). */
  step?: number;
  /** Allowed values (for string/source types). */
  options?: string[];
}

/** Where the indicator renders. */
export enum IndicatorPlacement {
  /** Overlay on the main price chart. */
  Overlay = "overlay",
  /** Separate pane below the chart. */
  Pane = "pane",
}

/** Metadata describing an indicator (for registry and browser). */
export interface IndicatorMetadata {
  /** Unique identifier (e.g., "sma", "rsi", "macd"). */
  id: string;
  /** Display name (e.g., "Simple Moving Average"). */
  name: string;
  /** Short description. */
  description: string;
  /** Category for grouping (e.g., "Moving Averages", "Oscillators"). */
  category: string;
  /** Where this indicator renders. */
  placement: IndicatorPlacement;
  /** Parameter definitions with defaults. */
  params: IndicatorParam[];
  /** Number of output series (e.g., MACD has 3: MACD line, signal, histogram). */
  outputCount: number;
  /** Output series labels. */
  outputLabels: string[];
  /** Default output colors (OKLCH strings). */
  defaultColors: string[];
  /** Whether this indicator supports incremental (single-bar) updates. */
  incrementalSupport?: boolean;
}

/** Active indicator instance on a chart. */
export interface IndicatorConfig {
  /** Indicator identifier (references IndicatorMetadata.id). */
  indicatorId: string;
  /** User-configured parameter values. */
  params: Record<string, number | string | boolean>;
  /** Whether this indicator is visible. */
  visible: boolean;
  /** Output line colors (overrides defaults). */
  colors: string[];
  /** Output line widths in pixels. */
  lineWidths: number[];
}

/** Single output value from an indicator at one bar. */
export interface IndicatorOutputValue {
  /** Bar timestamp. */
  timestamp: number;
  /** Computed values (one per output series). */
  values: (number | null)[];
  /** Optional per-series color hints for directional coloring (e.g., MACD histogram). */
  colorHints?: (string | null)[];
}

/** Full output from computing an indicator over a data range. */
export interface IndicatorOutput {
  /** Indicator instance identifier. */
  indicatorId: string;
  /** Computed values for each bar. */
  data: IndicatorOutputValue[];
}

/** Indicator compute function signature. */
export type IndicatorFunction = (
  data: OHLCV[],
  params: Record<string, number | string | boolean>
) => IndicatorOutput;
