import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** JMA — Jurik Moving Average (approximation). Uses adaptive smoothing with phase shift. */
export function jma(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 7;
  const phase = (params["phase"] as number | undefined) ?? 50;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("jma", timestamps, [result]);
  }

  const phaseRatio = phase < -100 ? 0.5 : phase > 100 ? 2.5 : phase / 100 + 1.5;
  const beta = 0.45 * (period - 1) / (0.45 * (period - 1) + 2);
  const alpha = Math.pow(beta, 3);

  let e0 = src[0]!;
  let e1 = 0;
  let e2 = 0;
  result[0] = src[0]!;

  for (let i = 1; i < len; i++) {
    e0 = (1 - alpha) * src[i]! + alpha * e0;
    e1 = (src[i]! - e0) * (1 - beta) + beta * e1;
    e2 = (e0 + phaseRatio * e1 - result[i - 1]!) * Math.pow(1 - alpha, 2) + Math.pow(alpha, 2) * e2;
    result[i] = result[i - 1]! + e2;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("jma", timestamps, [result]);
}
