import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

export function tema(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const ema1 = emaArray(src, period);

  const validEma1 = ema1.filter((v) => !Number.isNaN(v));
  const ema2 = emaArray(validEma1, period);

  const validEma2 = ema2.filter((v) => !Number.isNaN(v));
  const ema3 = emaArray(validEma2, period);

  const len = src.length;
  const result = fillNaN(len);
  const offset1 = period - 1;
  const offset2 = offset1 * 2;
  const offset3 = offset1 * 3;

  for (let i = offset3; i < len; i++) {
    const e1 = ema1[i]!;
    const e2 = ema2[i - offset1]!;
    const e3 = ema3[i - offset2]!;
    result[i] = 3 * e1 - 3 * e2 + e3;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("tema", timestamps, [result]);
}
