import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput } from "../utils";

/** Price Volume Trend. */
export function pvt(
  data: OHLCV[],
  _params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const len = data.length;
  const result = new Array<number>(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("pvt", timestamps, [result]);
  }

  result[0] = 0;

  for (let i = 1; i < len; i++) {
    const prevClose = data[i - 1]!.close;
    const pctChange = prevClose === 0 ? 0 : (data[i]!.close - prevClose) / prevClose;
    result[i] = result[i - 1]! + pctChange * data[i]!.volume;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("pvt", timestamps, [result]);
}
