import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Elder's Force Index — combines price change and volume. */
export function elderForce(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 13;
  const len = data.length;

  if (len < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("elder-force", timestamps, [fillNaN(len)]);
  }

  const rawForce = new Array<number>(len);
  rawForce[0] = 0;

  for (let i = 1; i < len; i++) {
    rawForce[i] = (data[i]!.close - data[i - 1]!.close) * data[i]!.volume;
  }

  const result = emaArray(rawForce, period);
  const timestamps = extractTimestamps(data);
  return buildOutput("elder-force", timestamps, [result]);
}
