import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN } from "../utils";

export function alma(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 9;
  const offset = (params["offset"] as number | undefined) ?? 0.85;
  const sigma = (params["sigma"] as number | undefined) ?? 6;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("alma", timestamps, [result]);
  }

  const m = offset * (period - 1);
  const s = period / sigma;

  const weights = new Array<number>(period);
  let weightSum = 0;
  for (let i = 0; i < period; i++) {
    const w = Math.exp(-((i - m) * (i - m)) / (2 * s * s));
    weights[i] = w;
    weightSum += w;
  }

  for (let i = period - 1; i < len; i++) {
    let sum = 0;
    for (let j = 0; j < period; j++) {
      sum += src[i - period + 1 + j]! * weights[j]!;
    }
    result[i] = sum / weightSum;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("alma", timestamps, [result]);
}
