import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Chaikin Oscillator — difference between fast and slow EMA of AD line. */
export function chaikinOsc(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const fastPeriod = (params["fastPeriod"] as number | undefined) ?? 3;
  const slowPeriod = (params["slowPeriod"] as number | undefined) ?? 10;

  const len = data.length;
  const adLine = new Array<number>(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("chaikin-osc", timestamps, [fillNaN(len)]);
  }

  let cumulative = 0;
  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const range = bar.high - bar.low;
    const mfMultiplier = range === 0 ? 0 : ((bar.close - bar.low) - (bar.high - bar.close)) / range;
    cumulative += mfMultiplier * bar.volume;
    adLine[i] = cumulative;
  }

  const fastEma = emaArray(adLine, fastPeriod);
  const slowEma = emaArray(adLine, slowPeriod);

  const result = fillNaN(len);
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(fastEma[i]!) && !Number.isNaN(slowEma[i]!)) {
      result[i] = fastEma[i]! - slowEma[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("chaikin-osc", timestamps, [result]);
}
