import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Historical Volatility — annualized standard deviation of log returns. */
export function histVol(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const annualFactor = (params["annualFactor"] as number | undefined) ?? 365;

  const len = data.length;
  const result = fillNaN(len);

  if (len < period + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("hist-vol", timestamps, [result]);
  }

  const logReturns = fillNaN(len);
  for (let i = 1; i < len; i++) {
    const prev = data[i - 1]!.close;
    if (prev > 0 && data[i]!.close > 0) {
      logReturns[i] = Math.log(data[i]!.close / prev);
    }
  }

  for (let i = period; i < len; i++) {
    let sum = 0;
    let count = 0;
    for (let j = i - period + 1; j <= i; j++) {
      if (!Number.isNaN(logReturns[j]!)) {
        sum += logReturns[j]!;
        count++;
      }
    }

    if (count < 2) continue;

    const mean = sum / count;
    let sumSqDiff = 0;
    for (let j = i - period + 1; j <= i; j++) {
      if (!Number.isNaN(logReturns[j]!)) {
        const diff = logReturns[j]! - mean;
        sumSqDiff += diff * diff;
      }
    }

    result[i] = Math.sqrt((sumSqDiff / (count - 1)) * annualFactor) * 100;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("hist-vol", timestamps, [result]);
}
