import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Fisher Transform — converts prices to Gaussian normal distribution. */
export function fisherTransform(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 10;
  const len = data.length;

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("fisher-transform", timestamps, [fillNaN(len), fillNaN(len)]);
  }

  const result = fillNaN(len);
  const trigger = fillNaN(len);
  let prevFisher = 0;
  let prevVal = 0;

  for (let i = period - 1; i < len; i++) {
    let hh = -Infinity;
    let ll = Infinity;
    for (let j = i - period + 1; j <= i; j++) {
      const hl2 = (data[j]!.high + data[j]!.low) / 2;
      if (hl2 > hh) hh = hl2;
      if (hl2 < ll) ll = hl2;
    }

    const hl2 = (data[i]!.high + data[i]!.low) / 2;
    const range = hh - ll;
    const normalizedVal = range === 0 ? 0 : ((hl2 - ll) / range - 0.5) * 2;
    const clampedVal = Math.max(-0.999, Math.min(0.999, 0.5 * normalizedVal + 0.5 * prevVal));

    const fisher = 0.5 * Math.log((1 + clampedVal) / (1 - clampedVal)) + 0.5 * prevFisher;

    trigger[i] = prevFisher;
    result[i] = fisher;
    prevFisher = fisher;
    prevVal = clampedVal;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("fisher-transform", timestamps, [result, trigger]);
}
