import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { crsi } from "../oscillators/crsi";

/** Connors RSI — alias for CRSI. */
export function connorsRsi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = crsi(data, params);
  return { indicatorId: "connors-rsi", data: result.data };
}
