import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Ultimate Oscillator — combines three timeframes. */
export function ultimateOscillator(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period1 = (params["period1"] as number | undefined) ?? 7;
  const period2 = (params["period2"] as number | undefined) ?? 14;
  const period3 = (params["period3"] as number | undefined) ?? 28;

  const len = data.length;
  const result = fillNaN(len);
  const maxPeriod = Math.max(period1, period2, period3);

  if (len < maxPeriod + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("ultimate-oscillator", timestamps, [result]);
  }

  const bp = new Array<number>(len);
  const tr = new Array<number>(len);

  bp[0] = 0;
  tr[0] = data[0]!.high - data[0]!.low;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const prevClose = data[i - 1]!.close;
    const trueLow = Math.min(bar.low, prevClose);
    const trueHigh = Math.max(bar.high, prevClose);
    bp[i] = bar.close - trueLow;
    tr[i] = trueHigh - trueLow;
  }

  for (let i = maxPeriod; i < len; i++) {
    let bpSum1 = 0, trSum1 = 0;
    let bpSum2 = 0, trSum2 = 0;
    let bpSum3 = 0, trSum3 = 0;

    for (let j = i - period1 + 1; j <= i; j++) {
      bpSum1 += bp[j]!;
      trSum1 += tr[j]!;
    }
    for (let j = i - period2 + 1; j <= i; j++) {
      bpSum2 += bp[j]!;
      trSum2 += tr[j]!;
    }
    for (let j = i - period3 + 1; j <= i; j++) {
      bpSum3 += bp[j]!;
      trSum3 += tr[j]!;
    }

    const avg1 = trSum1 === 0 ? 0 : bpSum1 / trSum1;
    const avg2 = trSum2 === 0 ? 0 : bpSum2 / trSum2;
    const avg3 = trSum3 === 0 ? 0 : bpSum3 / trSum3;

    result[i] = ((4 * avg1 + 2 * avg2 + avg3) / 7) * 100;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("ultimate-oscillator", timestamps, [result]);
}
