import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Volume Oscillator — percentage difference between fast and slow volume EMAs. */
export function volOsc(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const fastPeriod = (params["fastPeriod"] as number | undefined) ?? 5;
  const slowPeriod = (params["slowPeriod"] as number | undefined) ?? 10;

  const len = data.length;
  const volumes = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    volumes[i] = data[i]!.volume;
  }

  const fastEma = emaArray(volumes, fastPeriod);
  const slowEma = emaArray(volumes, slowPeriod);

  const result = fillNaN(len);
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(fastEma[i]!) && !Number.isNaN(slowEma[i]!) && slowEma[i]! !== 0) {
      result[i] = ((fastEma[i]! - slowEma[i]!) / slowEma[i]!) * 100;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vol-osc", timestamps, [result]);
}
