import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Chaikin Money Flow. */
export function cmf(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const len = data.length;
  const result = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("cmf", timestamps, [result]);
  }

  const mfv = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const range = bar.high - bar.low;
    const mfMultiplier = range === 0 ? 0 : ((bar.close - bar.low) - (bar.high - bar.close)) / range;
    mfv[i] = mfMultiplier * bar.volume;
  }

  let sumMfv = 0;
  let sumVol = 0;
  for (let i = 0; i < period; i++) {
    sumMfv += mfv[i]!;
    sumVol += data[i]!.volume;
  }
  result[period - 1] = sumVol === 0 ? 0 : sumMfv / sumVol;

  for (let i = period; i < len; i++) {
    sumMfv += mfv[i]! - mfv[i - period]!;
    sumVol += data[i]!.volume - data[i - period]!.volume;
    result[i] = sumVol === 0 ? 0 : sumMfv / sumVol;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("cmf", timestamps, [result]);
}
