import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, smaArray, fillNaN } from "../utils";

/** Mining Difficulty — proxy using volume-weighted price momentum. */
export function miningDifficulty(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;

  const len = data.length;
  const vpRatio = new Array<number>(len);

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    vpRatio[i] = bar.close * bar.volume;
  }

  const smoothed = smaArray(vpRatio, period);
  const timestamps = extractTimestamps(data);
  return buildOutput("mining-difficulty", timestamps, [smoothed]);
}
