/**
 * Web Worker entry point for batch indicator computation.
 *
 * Receives OHLCV data as transferred Float64Array buffers, reconstructs
 * the bar array, runs the indicator compute function, and returns the
 * result with transferable output buffers.
 *
 * This module is imported via `new Worker(new URL(..., import.meta.url))`
 * in the chart app's Vite build — it must be self-contained.
 */

import type { OHLCV, IndicatorOutput, IndicatorOutputValue } from "@deskmodal/core";
import { createIndicatorRegistry, registerAllIndicators } from "@deskmodal/indicators";
import type { IndicatorRegistry } from "@deskmodal/indicators";

/** Worker global scope with transfer-list postMessage overload. */
interface WorkerSelf {
  postMessage(message: unknown, transfer: Transferable[]): void;
  postMessage(message: unknown): void;
  addEventListener(type: 'message', listener: (ev: MessageEvent) => void): void;
}

const ctx: WorkerSelf = self as unknown as WorkerSelf;

/** Payload sent from the main thread. */
export interface IndicatorWorkerRequest {
  readonly type: "compute";
  /** Correlation ID for matching responses. */
  readonly id: string;
  /** Indicator ID from the registry. */
  readonly indicatorId: string;
  /** Transferred Float64Array buffers (timestamps, opens, highs, lows, closes, volumes). */
  readonly timestamps: ArrayBuffer;
  readonly opens: ArrayBuffer;
  readonly highs: ArrayBuffer;
  readonly lows: ArrayBuffer;
  readonly closes: ArrayBuffer;
  readonly volumes: ArrayBuffer;
  /** Indicator parameters. */
  readonly params: Record<string, number | string | boolean>;
}

/** Successful result sent back to the main thread. */
export interface IndicatorWorkerResult {
  readonly type: "result";
  readonly id: string;
  readonly output: IndicatorOutput;
  /** Flattened output values as a transferable Float64Array. */
  readonly valueBuffer: ArrayBuffer;
  /** Number of output series per bar (outputCount). */
  readonly seriesCount: number;
}

/** Error result sent back to the main thread. */
export interface IndicatorWorkerError {
  readonly type: "error";
  readonly id: string;
  readonly error: string;
}

/** Progress update sent during multi-step indicators. */
export interface IndicatorWorkerProgress {
  readonly type: "progress";
  readonly id: string;
  readonly progress: number;
}

export type IndicatorWorkerOutbound =
  | IndicatorWorkerResult
  | IndicatorWorkerError
  | IndicatorWorkerProgress;

/** Reconstruct OHLCV[] from transferred ArrayBuffers. */
function reconstructOHLCV(
  timestamps: ArrayBuffer,
  opens: ArrayBuffer,
  highs: ArrayBuffer,
  lows: ArrayBuffer,
  closes: ArrayBuffer,
  volumes: ArrayBuffer,
): OHLCV[] {
  const ts = new Float64Array(timestamps);
  const o = new Float64Array(opens);
  const h = new Float64Array(highs);
  const l = new Float64Array(lows);
  const c = new Float64Array(closes);
  const v = new Float64Array(volumes);

  const len = ts.length;
  const result: OHLCV[] = new Array(len);
  for (let i = 0; i < len; i++) {
    result[i] = {
      timestamp: ts[i]!,
      open: o[i]!,
      high: h[i]!,
      low: l[i]!,
      close: c[i]!,
      volume: v[i]!,
    };
  }
  return result;
}

/**
 * Flatten IndicatorOutput data into a single Float64Array for zero-copy transfer.
 * Layout: for each bar, `seriesCount` values packed sequentially.
 * Null values are encoded as NaN.
 */
function flattenOutputValues(
  data: IndicatorOutputValue[],
  seriesCount: number,
): Float64Array {
  const buf = new Float64Array(data.length * seriesCount);
  for (let i = 0; i < data.length; i++) {
    const entry = data[i]!;
    const base = i * seriesCount;
    for (let s = 0; s < seriesCount; s++) {
      const val = entry.values[s];
      buf[base + s] = val === null || val === undefined ? NaN : val;
    }
  }
  return buf;
}

let registry: IndicatorRegistry | null = null;

function getRegistry(): IndicatorRegistry {
  if (registry === null) {
    registry = createIndicatorRegistry();
    registerAllIndicators(registry);
  }
  return registry;
}

/**
 * Handle incoming compute request.
 */
function handleMessage(msg: IndicatorWorkerRequest): void {
  const { id, indicatorId, timestamps, opens, highs, lows, closes, volumes, params } = msg;

  try {
    const reg = getRegistry();
    const computeFn = reg.get(indicatorId);
    if (computeFn === undefined) {
      const errorMsg: IndicatorWorkerError = {
        type: "error",
        id,
        error: `Unknown indicator: ${indicatorId}`,
      };
      ctx.postMessage(errorMsg);
      return;
    }

    const ohlcv = reconstructOHLCV(timestamps, opens, highs, lows, closes, volumes);
    const output = computeFn(ohlcv, params);

    const seriesCount = output.data.length > 0
      ? output.data[0]!.values.length
      : 0;

    const valueBuf = flattenOutputValues(output.data, seriesCount);

    const result: IndicatorWorkerResult = {
      type: "result",
      id,
      output,
      valueBuffer: valueBuf.buffer as ArrayBuffer,
      seriesCount,
    };

    ctx.postMessage(result, [valueBuf.buffer as ArrayBuffer]);
  } catch (err: unknown) {
    const errorMsg: IndicatorWorkerError = {
      type: "error",
      id,
      error: err instanceof Error ? err.message : String(err),
    };
    ctx.postMessage(errorMsg);
  }
}

ctx.addEventListener("message", (event: MessageEvent<IndicatorWorkerRequest>) => {
  const msg = event.data;
  if (msg.type === "compute") {
    handleMessage(msg);
  }
});
