import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/**
 * SMA that operates on a full-length array preserving index alignment.
 * NaN values are skipped in the window average but positions are kept.
 * A valid output requires `period` consecutive non-NaN values.
 */
function smaPreservingNaN(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len === 0 || period < 1) return result;

  let validCount = 0;
  let sum = 0;

  for (let i = 0; i < len; i++) {
    const v = values[i]!;
    if (!Number.isNaN(v)) {
      validCount++;
      sum += v;
    }

    if (i >= period) {
      const old = values[i - period]!;
      if (!Number.isNaN(old)) {
        validCount--;
        sum -= old;
      }
    }

    if (validCount === period) {
      result[i] = sum / period;
    }
  }

  return result;
}

/** Stochastic Oscillator (%K and %D). */
export function stochastic(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const kPeriod = (params["kPeriod"] as number | undefined) ?? 14;
  const dPeriod = (params["dPeriod"] as number | undefined) ?? 3;
  const smooth = (params["smooth"] as number | undefined) ?? 3;

  const len = data.length;
  const rawK = fillNaN(len);

  for (let i = kPeriod - 1; i < len; i++) {
    let hh = -Infinity;
    let ll = Infinity;
    for (let j = i - kPeriod + 1; j <= i; j++) {
      if (data[j]!.high > hh) hh = data[j]!.high;
      if (data[j]!.low < ll) ll = data[j]!.low;
    }
    const range = hh - ll;
    rawK[i] = range === 0 ? 50 : ((data[i]!.close - ll) / range) * 100;
  }

  /** Smooth %K in-place preserving index alignment (no filter/reindex). */
  const kLine = smooth > 1 ? smaPreservingNaN(rawK, smooth) : rawK.slice();

  /** %D = SMA of %K, also preserving alignment. */
  const dLine = smaPreservingNaN(kLine, dPeriod);

  const timestamps = extractTimestamps(data);
  return buildOutput("stochastic", timestamps, [kLine, dLine]);
}
