import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput } from "../utils";

/** On-Balance Volume. */
export function obv(
  data: OHLCV[],
  _params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const len = data.length;
  const result = new Array<number>(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("obv", timestamps, [result]);
  }

  result[0] = data[0]!.volume;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const prevClose = data[i - 1]!.close;

    if (bar.close > prevClose) {
      result[i] = result[i - 1]! + bar.volume;
    } else if (bar.close < prevClose) {
      result[i] = result[i - 1]! - bar.volume;
    } else {
      result[i] = result[i - 1]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("obv", timestamps, [result]);
}
