import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Vortex Indicator — measures positive and negative trend movement. */
export function vortex(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const len = data.length;

  const viPlus = fillNaN(len);
  const viMinus = fillNaN(len);

  if (len < period + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("vortex", timestamps, [viPlus, viMinus]);
  }

  for (let i = period; i < len; i++) {
    let vmPlus = 0;
    let vmMinus = 0;
    let trSum = 0;

    for (let j = i - period + 1; j <= i; j++) {
      vmPlus += Math.abs(data[j]!.high - data[j - 1]!.low);
      vmMinus += Math.abs(data[j]!.low - data[j - 1]!.high);

      const hl = data[j]!.high - data[j]!.low;
      const hc = Math.abs(data[j]!.high - data[j - 1]!.close);
      const lc = Math.abs(data[j]!.low - data[j - 1]!.close);
      trSum += Math.max(hl, hc, lc);
    }

    viPlus[i] = trSum === 0 ? 0 : vmPlus / trSum;
    viMinus[i] = trSum === 0 ? 0 : vmMinus / trSum;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vortex", timestamps, [viPlus, viMinus]);
}
