import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Klinger Volume Oscillator. */
export function klinger(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const fastPeriod = (params["fastPeriod"] as number | undefined) ?? 34;
  const slowPeriod = (params["slowPeriod"] as number | undefined) ?? 55;
  const signalPeriod = (params["signalPeriod"] as number | undefined) ?? 13;

  const len = data.length;

  if (len < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("klinger", timestamps, [fillNaN(len), fillNaN(len)]);
  }

  const vf = new Array<number>(len);
  vf[0] = 0;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const prevBar = data[i - 1]!;
    const hlc = bar.high + bar.low + bar.close;
    const prevHlc = prevBar.high + prevBar.low + prevBar.close;
    const trend = hlc >= prevHlc ? 1 : -1;

    const dm = bar.high - bar.low;
    const cm = i >= 2 ? dm + Math.abs(dm) : dm;

    vf[i] = cm === 0 ? 0 : bar.volume * Math.abs(2 * (dm / cm) - 1) * trend * 100;
  }

  const fastEma = emaArray(vf, fastPeriod);
  const slowEma = emaArray(vf, slowPeriod);

  const kvo = fillNaN(len);
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(fastEma[i]!) && !Number.isNaN(slowEma[i]!)) {
      kvo[i] = fastEma[i]! - slowEma[i]!;
    }
  }

  const validKvo = kvo.filter((v) => !Number.isNaN(v));
  const signalValues = emaArray(validKvo, signalPeriod);
  const signalLine = fillNaN(len);

  let sigIdx = 0;
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(kvo[i]!)) {
      if (sigIdx < signalValues.length && !Number.isNaN(signalValues[sigIdx]!)) {
        signalLine[i] = signalValues[sigIdx]!;
      }
      sigIdx++;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("klinger", timestamps, [kvo, signalLine]);
}
