import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Cumulative Volume Index — running total of volume direction. */
export function cvi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const len = data.length;

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("cvi", timestamps, [fillNaN(len)]);
  }

  const hlDiff = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    hlDiff[i] = data[i]!.high - data[i]!.low;
  }

  const emaHL = emaArray(hlDiff, period);

  const result = fillNaN(len);
  for (let i = period; i < len; i++) {
    if (!Number.isNaN(emaHL[i]!) && !Number.isNaN(emaHL[i - period]!) && emaHL[i - period]! !== 0) {
      result[i] = ((emaHL[i]! - emaHL[i - period]!) / emaHL[i - period]!) * 100;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("cvi", timestamps, [result]);
}
