import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, wmaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

export function hma(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const halfPeriod = Math.max(1, Math.floor(period / 2));
  const sqrtPeriod = Math.max(1, Math.floor(Math.sqrt(period)));

  const wmaHalf = wmaArray(src, halfPeriod);
  const wmaFull = wmaArray(src, period);

  const len = src.length;
  const diff: number[] = fillNaN(len);

  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(wmaHalf[i]!) && !Number.isNaN(wmaFull[i]!)) {
      diff[i] = 2 * wmaHalf[i]! - wmaFull[i]!;
    }
  }

  const validDiff = diff.filter((v) => !Number.isNaN(v));
  const hmaValues = wmaArray(validDiff, sqrtPeriod);

  const result = fillNaN(len);
  const startOffset = period - 1;

  let hmaIdx = 0;
  for (let i = startOffset; i < len; i++) {
    if (hmaIdx < hmaValues.length) {
      result[i] = hmaValues[hmaIdx]!;
      hmaIdx++;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("hma", timestamps, [result]);
}
