import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { dpo } from "../oscillators/dpo";

/** Detrended Oscillator — alias for DPO. */
export function detrendedOsc(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = dpo(data, params);
  return { indicatorId: "detrended-osc", data: result.data };
}
