import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { trueRange as computeTR, wilderSmooth, smaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Volatility Index — ATR as percentage of close price. */
export function volIdx(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;

  const len = data.length;
  const tr = computeTR(data);
  const atrValues = wilderSmooth(tr, period);

  const result = fillNaN(len);
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(atrValues[i]!) && data[i]!.close !== 0) {
      result[i] = (atrValues[i]! / data[i]!.close) * 100;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vol-idx", timestamps, [result]);
}
