import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Auto Fibonacci Retracement — finds swing high/low and plots fib levels. */
export function autoFibRetrace(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const lookback = (params["lookback"] as number | undefined) ?? 100;
  const len = data.length;

  const l0 = fillNaN(len); // 0%
  const l236 = fillNaN(len); // 23.6%
  const l382 = fillNaN(len); // 38.2%
  const l500 = fillNaN(len); // 50%
  const l618 = fillNaN(len); // 61.8%
  const l786 = fillNaN(len); // 78.6%
  const l100 = fillNaN(len); // 100%

  const period = Math.min(lookback, len);
  if (period < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("auto-fib-retrace", timestamps, [l0, l236, l382, l500, l618, l786, l100]);
  }

  for (let i = period - 1; i < len; i++) {
    let swingHigh = -Infinity;
    let swingLow = Infinity;
    const start = Math.max(0, i - period + 1);

    for (let j = start; j <= i; j++) {
      if (data[j]!.high > swingHigh) swingHigh = data[j]!.high;
      if (data[j]!.low < swingLow) swingLow = data[j]!.low;
    }

    const range = swingHigh - swingLow;
    const uptrend = data[i]!.close > (swingHigh + swingLow) / 2;

    if (uptrend) {
      l0[i] = swingHigh;
      l236[i] = swingHigh - range * 0.236;
      l382[i] = swingHigh - range * 0.382;
      l500[i] = swingHigh - range * 0.5;
      l618[i] = swingHigh - range * 0.618;
      l786[i] = swingHigh - range * 0.786;
      l100[i] = swingLow;
    } else {
      l0[i] = swingLow;
      l236[i] = swingLow + range * 0.236;
      l382[i] = swingLow + range * 0.382;
      l500[i] = swingLow + range * 0.5;
      l618[i] = swingLow + range * 0.618;
      l786[i] = swingLow + range * 0.786;
      l100[i] = swingHigh;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("auto-fib-retrace", timestamps, [l0, l236, l382, l500, l618, l786, l100]);
}
