import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { squeezeMomentum } from "../oscillators/squeeze-momentum";

/** Squeeze Pro — enhanced version of squeeze momentum. */
export function squeezePro(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = squeezeMomentum(data, {
    bbPeriod: (params["bbPeriod"] as number | undefined) ?? 20,
    bbMult: (params["bbMult"] as number | undefined) ?? 2,
    kcPeriod: (params["kcPeriod"] as number | undefined) ?? 20,
    kcMult: (params["kcMult"] as number | undefined) ?? 1.5,
    source: (params["source"] as string | undefined) ?? "close",
  });
  return { indicatorId: "squeeze-pro", data: result.data };
}
