import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { smaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** TRIN (Arms Index) — ratio of advancing/declining issues to up/down volume. */
export function trin(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const len = data.length;

  const rawTrin = new Array<number>(len);

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const isUp = bar.close >= bar.open;
    const upVol = isUp ? bar.volume : 0;
    const downVol = isUp ? 0 : bar.volume;

    if (downVol === 0) rawTrin[i] = 1;
    else rawTrin[i] = upVol / downVol;
  }

  const smoothed = smaArray(rawTrin, period);
  const timestamps = extractTimestamps(data);
  return buildOutput("trin", timestamps, [smoothed]);
}
