import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { vwma as vwmaCalc } from "../moving-averages/vwma";

/** VWMA indicator — Volume Weighted Moving Average as a pane indicator. */
export function vwmaIndicator(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = vwmaCalc(data, params);
  return { indicatorId: "vwma-indicator", data: result.data };
}
