import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { priceChannel } from "./price-channel";

/** Donchian Channel — alias for Price Channel. */
export function donchian(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = priceChannel(data, params);
  return { indicatorId: "donchian", data: result.data };
}
