import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Aroon — measures time since highest high and lowest low. */
export function aroon(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 25;
  const len = data.length;

  const aroonUp = fillNaN(len);
  const aroonDown = fillNaN(len);

  for (let i = period; i < len; i++) {
    let highIdx = i;
    let lowIdx = i;

    for (let j = i - period; j <= i; j++) {
      if (data[j]!.high > data[highIdx]!.high) highIdx = j;
      if (data[j]!.low < data[lowIdx]!.low) lowIdx = j;
    }

    aroonUp[i] = ((period - (i - highIdx)) / period) * 100;
    aroonDown[i] = ((period - (i - lowIdx)) / period) * 100;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("aroon", timestamps, [aroonUp, aroonDown]);
}
