import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { vpfr } from "./vpfr";

/** Volume Profile Visible Range — alias for VPFR (computed over visible data). */
export function vpvr(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = vpfr(data, params);
  return { indicatorId: "vpvr", data: result.data };
}
