import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { smaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Ease of Movement. */
export function eom(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const divisor = (params["divisor"] as number | undefined) ?? 10000;

  const len = data.length;
  const rawEom = fillNaN(len);

  if (len < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("eom", timestamps, [fillNaN(len)]);
  }

  rawEom[0] = 0;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const prevBar = data[i - 1]!;
    const distanceMoved = ((bar.high + bar.low) / 2) - ((prevBar.high + prevBar.low) / 2);
    const boxRatio = bar.high === bar.low ? 0 : (bar.volume / divisor) / (bar.high - bar.low);
    rawEom[i] = boxRatio === 0 ? 0 : distanceMoved / boxRatio;
  }

  const validEom = rawEom.filter((v) => !Number.isNaN(v));
  const smoothed = smaArray(validEom, period);

  const result = fillNaN(len);
  for (let i = 0; i < smoothed.length; i++) {
    const idx = i;
    if (idx < len && !Number.isNaN(smoothed[i]!)) {
      result[idx] = smoothed[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("eom", timestamps, [result]);
}
