import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, smaArray, emaArray, extractTimestamps, buildOutput, fillNaN, stdDev as computeStdDev } from "../utils";

/** Squeeze Momentum — identifies periods where BB is inside KC (squeeze). */
export function squeezeMomentum(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const bbPeriod = (params["bbPeriod"] as number | undefined) ?? 20;
  const bbMult = (params["bbMult"] as number | undefined) ?? 2;
  const kcPeriod = (params["kcPeriod"] as number | undefined) ?? 20;
  const kcMult = (params["kcMult"] as number | undefined) ?? 1.5;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = data.length;

  const bbSma = smaArray(src, bbPeriod);
  const bbStd = computeStdDev(src, bbPeriod);

  const closes = new Array<number>(len);
  for (let i = 0; i < len; i++) closes[i] = data[i]!.close;

  const tr = new Array<number>(len);
  tr[0] = data.length > 0 ? data[0]!.high - data[0]!.low : 0;
  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const pc = data[i - 1]!.close;
    tr[i] = Math.max(bar.high - bar.low, Math.abs(bar.high - pc), Math.abs(bar.low - pc));
  }
  const atrValues = emaArray(tr, kcPeriod);
  const kcMa = emaArray(closes, kcPeriod);

  const momentum = fillNaN(len);
  const sqzOn = fillNaN(len);

  for (let i = Math.max(bbPeriod, kcPeriod) - 1; i < len; i++) {
    if (Number.isNaN(bbSma[i]!) || Number.isNaN(bbStd[i]!) ||
        Number.isNaN(kcMa[i]!) || Number.isNaN(atrValues[i]!)) continue;

    const bbUpper = bbSma[i]! + bbMult * bbStd[i]!;
    const bbLower = bbSma[i]! - bbMult * bbStd[i]!;
    const kcUpper = kcMa[i]! + kcMult * atrValues[i]!;
    const kcLower = kcMa[i]! - kcMult * atrValues[i]!;

    sqzOn[i] = (bbLower > kcLower && bbUpper < kcUpper) ? 1 : 0;

    let hh = -Infinity, ll = Infinity;
    const lookback = kcPeriod;
    const start = Math.max(0, i - lookback + 1);
    for (let j = start; j <= i; j++) {
      if (data[j]!.high > hh) hh = data[j]!.high;
      if (data[j]!.low < ll) ll = data[j]!.low;
    }
    const midHL = (hh + ll) / 2;
    const midSMA = smaArray(src.slice(start, i + 1), lookback);
    const midSMAVal = midSMA.length > 0 ? midSMA[midSMA.length - 1]! : 0;
    const avgMid = Number.isNaN(midSMAVal) ? 0 : midSMAVal;

    momentum[i] = src[i]! - ((midHL + avgMid) / 2);
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("squeeze-momentum", timestamps, [momentum, sqzOn]);
}
