import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Bullish (above zero) histogram colors: bright for rising, dim for falling. */
const HISTOGRAM_BULLISH_RISING = "oklch(0.72 0.19 160)";
const HISTOGRAM_BULLISH_FALLING = "oklch(0.55 0.12 160)";
/** Bearish (below zero) histogram colors: bright for falling, dim for rising. */
const HISTOGRAM_BEARISH_FALLING = "oklch(0.65 0.22 25)";
const HISTOGRAM_BEARISH_RISING = "oklch(0.50 0.14 25)";

/** MACD — Moving Average Convergence Divergence. Outputs: MACD line, signal line, histogram. */
export function macd(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const fastPeriod = (params["fastPeriod"] as number | undefined) ?? 12;
  const slowPeriod = (params["slowPeriod"] as number | undefined) ?? 26;
  const signalPeriod = (params["signalPeriod"] as number | undefined) ?? 9;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  const fastEma = emaArray(src, fastPeriod);
  const slowEma = emaArray(src, slowPeriod);

  const macdLine = fillNaN(len);
  const macdValues: number[] = [];

  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(fastEma[i]!) && !Number.isNaN(slowEma[i]!)) {
      macdLine[i] = fastEma[i]! - slowEma[i]!;
      macdValues.push(macdLine[i]!);
    }
  }

  const signalArr = emaArray(macdValues, signalPeriod);

  const signalLine = fillNaN(len);
  const histogram = fillNaN(len);

  let macdIdx = 0;
  const offset = slowPeriod - 1;
  for (let i = offset; i < len; i++) {
    if (macdIdx < signalArr.length && !Number.isNaN(signalArr[macdIdx]!)) {
      signalLine[i] = signalArr[macdIdx]!;
      histogram[i] = macdLine[i]! - signalArr[macdIdx]!;
    }
    macdIdx++;
  }

  const timestamps = extractTimestamps(data);
  const output = buildOutput("macd", timestamps, [macdLine, signalLine, histogram]);

  // Add directional color hints for the histogram (series index 2)
  for (let i = 0; i < output.data.length; i++) {
    const entry = output.data[i]!;
    const histVal = entry.values[2] ?? null;
    if (histVal === null) {
      continue;
    }

    const prevHistVal = i > 0 ? (output.data[i - 1]!.values[2] ?? 0) : 0;
    const rising = histVal > prevHistVal;

    let histColor: string;
    if (histVal >= 0) {
      histColor = rising ? HISTOGRAM_BULLISH_RISING : HISTOGRAM_BULLISH_FALLING;
    } else {
      histColor = rising ? HISTOGRAM_BEARISH_RISING : HISTOGRAM_BEARISH_FALLING;
    }

    // colorHints array: null for MACD line and signal line, color for histogram
    entry.colorHints = [null, null, histColor];
  }

  return output;
}
