import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** True Strength Index. */
export function tsi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const longPeriod = (params["longPeriod"] as number | undefined) ?? 25;
  const shortPeriod = (params["shortPeriod"] as number | undefined) ?? 13;
  const signalPeriod = (params["signalPeriod"] as number | undefined) ?? 7;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  if (len < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("tsi", timestamps, [fillNaN(len), fillNaN(len)]);
  }

  const momentum = new Array<number>(len);
  momentum[0] = 0;
  const absMomentum = new Array<number>(len);
  absMomentum[0] = 0;

  for (let i = 1; i < len; i++) {
    momentum[i] = src[i]! - src[i - 1]!;
    absMomentum[i] = Math.abs(momentum[i]!);
  }

  const smoothMom1 = emaArray(momentum, longPeriod);
  const validSM1 = smoothMom1.filter((v) => !Number.isNaN(v));
  const smoothMom2 = emaArray(validSM1, shortPeriod);

  const smoothAbsMom1 = emaArray(absMomentum, longPeriod);
  const validSAM1 = smoothAbsMom1.filter((v) => !Number.isNaN(v));
  const smoothAbsMom2 = emaArray(validSAM1, shortPeriod);

  const tsiLine = fillNaN(len);
  const offset = longPeriod - 1 + shortPeriod - 1;

  for (let i = 0; i < smoothMom2.length; i++) {
    const idx = offset + i;
    if (idx < len && !Number.isNaN(smoothMom2[i]!) && !Number.isNaN(smoothAbsMom2[i]!)) {
      tsiLine[idx] = smoothAbsMom2[i]! === 0 ? 0 : (smoothMom2[i]! / smoothAbsMom2[i]!) * 100;
    }
  }

  const validTsi = tsiLine.filter((v) => !Number.isNaN(v));
  const signalValues = emaArray(validTsi, signalPeriod);
  const signalLine = fillNaN(len);

  let sigIdx = 0;
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(tsiLine[i]!)) {
      if (sigIdx < signalValues.length && !Number.isNaN(signalValues[sigIdx]!)) {
        signalLine[i] = signalValues[sigIdx]!;
      }
      sigIdx++;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("tsi", timestamps, [tsiLine, signalLine]);
}
