import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Ichimoku Cloud — Tenkan, Kijun, Senkou A, Senkou B, Chikou. */
export function ichimoku(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const tenkanPeriod = (params["tenkanPeriod"] as number | undefined) ?? 9;
  const kijunPeriod = (params["kijunPeriod"] as number | undefined) ?? 26;
  const senkouBPeriod = (params["senkouBPeriod"] as number | undefined) ?? 52;
  const displacement = (params["displacement"] as number | undefined) ?? 26;

  const len = data.length;
  /** Extended length to accommodate forward-projected Senkou spans. */
  const extLen = len + displacement;

  const donchian = (period: number, idx: number): number => {
    let hh = -Infinity;
    let ll = Infinity;
    const start = Math.max(0, idx - period + 1);
    for (let j = start; j <= idx; j++) {
      if (data[j]!.high > hh) hh = data[j]!.high;
      if (data[j]!.low < ll) ll = data[j]!.low;
    }
    return (hh + ll) / 2;
  };

  const tenkan = fillNaN(extLen);
  const kijun = fillNaN(extLen);
  const senkouA = fillNaN(extLen);
  const senkouB = fillNaN(extLen);
  const chikou = fillNaN(extLen);

  for (let i = tenkanPeriod - 1; i < len; i++) {
    tenkan[i] = donchian(tenkanPeriod, i);
  }

  for (let i = kijunPeriod - 1; i < len; i++) {
    kijun[i] = donchian(kijunPeriod, i);
  }

  /** Senkou A = (Tenkan + Kijun) / 2, displaced forward by `displacement` bars. */
  for (let i = kijunPeriod - 1; i < len; i++) {
    if (!Number.isNaN(tenkan[i]!) && !Number.isNaN(kijun[i]!)) {
      const fwdIdx = i + displacement;
      senkouA[fwdIdx] = (tenkan[i]! + kijun[i]!) / 2;
    }
  }

  /** Senkou B = Donchian midpoint over senkouBPeriod, displaced forward. */
  for (let i = senkouBPeriod - 1; i < len; i++) {
    const fwdIdx = i + displacement;
    senkouB[fwdIdx] = donchian(senkouBPeriod, i);
  }

  /** Chikou = close displaced backward by `displacement` bars. */
  for (let i = 0; i < len; i++) {
    const backIdx = i - displacement;
    if (backIdx >= 0) {
      chikou[backIdx] = data[i]!.close;
    }
  }

  /**
   * Build extended timestamps: real data timestamps + projected future timestamps.
   * Future bars are extrapolated from the average bar interval of the last bars.
   */
  const timestamps = extractTimestamps(data);
  if (len >= 2) {
    const lastTs = timestamps[len - 1]!;
    const avgInterval = (timestamps[len - 1]! - timestamps[0]!) / (len - 1);
    for (let i = 1; i <= displacement; i++) {
      timestamps.push(lastTs + avgInterval * i);
    }
  } else {
    for (let i = 0; i < displacement; i++) {
      timestamps.push((timestamps[len - 1] ?? 0) + (i + 1) * 60000);
    }
  }

  return buildOutput("ichimoku", timestamps, [tenkan, kijun, senkouA, senkouB, chikou]);
}
