import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Pivot Points — classic floor trader pivots: PP, S1, S2, S3, R1, R2, R3. */
export function pivotPoints(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const method = (params["method"] as string | undefined) ?? "traditional";
  const len = data.length;

  const pp = fillNaN(len);
  const s1 = fillNaN(len);
  const s2 = fillNaN(len);
  const s3 = fillNaN(len);
  const r1 = fillNaN(len);
  const r2 = fillNaN(len);
  const r3 = fillNaN(len);

  for (let i = 1; i < len; i++) {
    const prev = data[i - 1]!;
    const h = prev.high;
    const l = prev.low;
    const c = prev.close;

    if (method === "fibonacci") {
      const pivot = (h + l + c) / 3;
      const range = h - l;
      pp[i] = pivot;
      s1[i] = pivot - 0.382 * range;
      s2[i] = pivot - 0.618 * range;
      s3[i] = pivot - range;
      r1[i] = pivot + 0.382 * range;
      r2[i] = pivot + 0.618 * range;
      r3[i] = pivot + range;
    } else if (method === "woodie") {
      const pivot = (h + l + 2 * data[i]!.open) / 4;
      pp[i] = pivot;
      s1[i] = 2 * pivot - h;
      s2[i] = pivot - (h - l);
      s3[i] = l - 2 * (h - pivot);
      r1[i] = 2 * pivot - l;
      r2[i] = pivot + (h - l);
      r3[i] = h + 2 * (pivot - l);
    } else if (method === "camarilla") {
      const pivot = (h + l + c) / 3;
      const range = h - l;
      pp[i] = pivot;
      s1[i] = c - range * 1.1 / 12;
      s2[i] = c - range * 1.1 / 6;
      s3[i] = c - range * 1.1 / 4;
      r1[i] = c + range * 1.1 / 12;
      r2[i] = c + range * 1.1 / 6;
      r3[i] = c + range * 1.1 / 4;
    } else {
      const pivot = (h + l + c) / 3;
      pp[i] = pivot;
      s1[i] = 2 * pivot - h;
      s2[i] = pivot - (h - l);
      s3[i] = l - 2 * (h - pivot);
      r1[i] = 2 * pivot - l;
      r2[i] = pivot + (h - l);
      r3[i] = h + 2 * (pivot - l);
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("pivot-points", timestamps, [pp, r1, r2, r3, s1, s2, s3]);
}
