import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, trueRange as computeTR, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Keltner Channels — EMA-based bands with ATR multiplier. */
export function keltner(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const mult = (params["mult"] as number | undefined) ?? 1.5;
  const atrPeriod = (params["atrPeriod"] as number | undefined) ?? 10;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  const middle = emaArray(src, period);
  const tr = computeTR(data);
  const atrValues = emaArray(tr, atrPeriod);

  const upper = fillNaN(len);
  const lower = fillNaN(len);

  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(middle[i]!) && !Number.isNaN(atrValues[i]!)) {
      upper[i] = middle[i]! + mult * atrValues[i]!;
      lower[i] = middle[i]! - mult * atrValues[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("keltner", timestamps, [upper, middle, lower]);
}
