import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput } from "../utils";

/** Advance/Decline — cumulative count of advancing vs declining bars. */
export function advDecline(
  data: OHLCV[],
  _params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const len = data.length;
  const result = new Array<number>(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("adv-decline", timestamps, [result]);
  }

  result[0] = data[0]!.close >= data[0]!.open ? 1 : -1;

  for (let i = 1; i < len; i++) {
    const adv = data[i]!.close >= data[i - 1]!.close ? 1 : -1;
    result[i] = result[i - 1]! + adv;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("adv-decline", timestamps, [result]);
}
