import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** ZigZag — connects swing points with minimum percentage deviation. */
export function zigzag(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const deviation = (params["deviation"] as number | undefined) ?? 5;
  const len = data.length;
  const result = fillNaN(len);

  if (len < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("zigzag", timestamps, [result]);
  }

  const threshold = deviation / 100;

  interface Pivot { idx: number; price: number; isHigh: boolean }
  const pivots: Pivot[] = [];

  let lastPivot: Pivot = { idx: 0, price: data[0]!.close, isHigh: true };
  let candidatePivot: Pivot = { idx: 0, price: data[0]!.close, isHigh: false };
  let searchingHigh = true;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;

    if (searchingHigh) {
      if (bar.high > candidatePivot.price) {
        candidatePivot = { idx: i, price: bar.high, isHigh: true };
      }
      if (bar.low < candidatePivot.price * (1 - threshold)) {
        pivots.push(candidatePivot);
        lastPivot = candidatePivot;
        candidatePivot = { idx: i, price: bar.low, isHigh: false };
        searchingHigh = false;
      }
    } else {
      if (bar.low < candidatePivot.price) {
        candidatePivot = { idx: i, price: bar.low, isHigh: false };
      }
      if (bar.high > candidatePivot.price * (1 + threshold)) {
        pivots.push(candidatePivot);
        lastPivot = candidatePivot;
        candidatePivot = { idx: i, price: bar.high, isHigh: true };
        searchingHigh = true;
      }
    }
  }
  pivots.push(candidatePivot);

  for (let p = 0; p < pivots.length - 1; p++) {
    const p1 = pivots[p]!;
    const p2 = pivots[p + 1]!;
    const indexRange = p2.idx - p1.idx;

    for (let i = p1.idx; i <= p2.idx; i++) {
      const fraction = indexRange === 0 ? 0 : (i - p1.idx) / indexRange;
      result[i] = p1.price + fraction * (p2.price - p1.price);
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("zigzag", timestamps, [result]);
}
