import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** T3 — Tillson T3 triple-smoothed EMA with volume factor. */
export function t3(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 5;
  const volumeFactor = (params["volumeFactor"] as number | undefined) ?? 0.7;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  const c1 = -(volumeFactor * volumeFactor * volumeFactor);
  const c2 = 3 * volumeFactor * volumeFactor + 3 * volumeFactor * volumeFactor * volumeFactor;
  const c3 = -6 * volumeFactor * volumeFactor - 3 * volumeFactor - 3 * volumeFactor * volumeFactor * volumeFactor;
  const c4 = 1 + 3 * volumeFactor + volumeFactor * volumeFactor * volumeFactor + 3 * volumeFactor * volumeFactor;

  const e1 = emaArray(src, period);
  const e1v = e1.filter((v) => !Number.isNaN(v));
  const e2 = emaArray(e1v, period);
  const e2v = e2.filter((v) => !Number.isNaN(v));
  const e3 = emaArray(e2v, period);
  const e3v = e3.filter((v) => !Number.isNaN(v));
  const e4 = emaArray(e3v, period);
  const e4v = e4.filter((v) => !Number.isNaN(v));
  const e5 = emaArray(e4v, period);
  const e5v = e5.filter((v) => !Number.isNaN(v));
  const e6 = emaArray(e5v, period);

  const result = fillNaN(len);
  const offset = (period - 1) * 6;

  for (let i = offset; i < len; i++) {
    const idx = i - offset;
    if (idx >= 0 && idx < e6.length && !Number.isNaN(e6[idx]!)) {
      const eIdx3 = i - (period - 1) * 3;
      const eIdx4 = i - (period - 1) * 4;
      const eIdx5 = i - (period - 1) * 5;

      if (eIdx3 >= 0 && eIdx3 < e3v.length &&
          eIdx4 >= 0 && eIdx4 < e4v.length &&
          eIdx5 >= 0 && eIdx5 < e5v.length) {
        result[i] = c1 * e6[idx]! + c2 * e5v[eIdx5 < e5v.length ? eIdx5 : e5v.length - 1]! +
                     c3 * e4v[eIdx4 < e4v.length ? eIdx4 : e4v.length - 1]! +
                     c4 * e3v[eIdx3 < e3v.length ? eIdx3 : e3v.length - 1]!;
      }
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("t3", timestamps, [result]);
}
