import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** McClellan Oscillator — breadth oscillator using advancing/declining proxy. */
export function mcclellan(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const fastPeriod = (params["fastPeriod"] as number | undefined) ?? 19;
  const slowPeriod = (params["slowPeriod"] as number | undefined) ?? 39;

  const len = data.length;
  const breadth = new Array<number>(len);

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    breadth[i] = bar.close >= bar.open ? 1 : -1;
  }

  const fastEma = emaArray(breadth, fastPeriod);
  const slowEma = emaArray(breadth, slowPeriod);

  const result = fillNaN(len);
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(fastEma[i]!) && !Number.isNaN(slowEma[i]!)) {
      result[i] = fastEma[i]! - slowEma[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("mcclellan", timestamps, [result]);
}
