import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN, smaArray } from "../utils";

/** Stochastic RSI — applies stochastic formula to RSI values. */
export function stochRsi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const rsiPeriod = (params["rsiPeriod"] as number | undefined) ?? 14;
  const stochPeriod = (params["stochPeriod"] as number | undefined) ?? 14;
  const kSmooth = (params["kSmooth"] as number | undefined) ?? 3;
  const dSmooth = (params["dSmooth"] as number | undefined) ?? 3;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  if (len < rsiPeriod + stochPeriod + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("stoch-rsi", timestamps, [fillNaN(len), fillNaN(len)]);
  }

  const rsiValues = fillNaN(len);
  let avgGain = 0;
  let avgLoss = 0;

  for (let i = 1; i <= rsiPeriod; i++) {
    const change = src[i]! - src[i - 1]!;
    if (change > 0) avgGain += change;
    else avgLoss += Math.abs(change);
  }
  avgGain /= rsiPeriod;
  avgLoss /= rsiPeriod;
  rsiValues[rsiPeriod] = avgLoss === 0 ? 100 : 100 - 100 / (1 + avgGain / avgLoss);

  for (let i = rsiPeriod + 1; i < len; i++) {
    const change = src[i]! - src[i - 1]!;
    const gain = change > 0 ? change : 0;
    const loss = change < 0 ? Math.abs(change) : 0;
    avgGain = (avgGain * (rsiPeriod - 1) + gain) / rsiPeriod;
    avgLoss = (avgLoss * (rsiPeriod - 1) + loss) / rsiPeriod;
    rsiValues[i] = avgLoss === 0 ? 100 : 100 - 100 / (1 + avgGain / avgLoss);
  }

  const stochK = fillNaN(len);
  for (let i = rsiPeriod + stochPeriod - 1; i < len; i++) {
    let hh = -Infinity;
    let ll = Infinity;
    for (let j = i - stochPeriod + 1; j <= i; j++) {
      const v = rsiValues[j]!;
      if (!Number.isNaN(v)) {
        if (v > hh) hh = v;
        if (v < ll) ll = v;
      }
    }
    const range = hh - ll;
    stochK[i] = range === 0 ? 50 : ((rsiValues[i]! - ll) / range) * 100;
  }

  const validK = stochK.filter((v) => !Number.isNaN(v));
  const smoothedK = kSmooth > 1 ? smaArray(validK, kSmooth) : validK;
  const smoothedD = smaArray(smoothedK.filter((v) => !Number.isNaN(v)), dSmooth);

  const kLine = fillNaN(len);
  const dLine = fillNaN(len);

  const kStart = rsiPeriod + stochPeriod - 1 + (kSmooth > 1 ? kSmooth - 1 : 0);
  for (let i = 0; i < smoothedK.length; i++) {
    const idx = kStart + i;
    if (idx < len && !Number.isNaN(smoothedK[i]!)) {
      kLine[idx] = smoothedK[i]!;
    }
  }

  const dStart = kStart + dSmooth - 1;
  for (let i = 0; i < smoothedD.length; i++) {
    const idx = dStart + i;
    if (idx < len && !Number.isNaN(smoothedD[i]!)) {
      dLine[idx] = smoothedD[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("stoch-rsi", timestamps, [kLine, dLine]);
}
