import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Chop Zone — EMA-based colored trend zone indicator. */
export function chopZone(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 30;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const emaValues = emaArray(src, period);

  const result = fillNaN(len);

  for (let i = 1; i < len; i++) {
    if (!Number.isNaN(emaValues[i]!) && !Number.isNaN(emaValues[i - 1]!)) {
      const angle = Math.atan2(emaValues[i]! - emaValues[i - 1]!, 1) * (180 / Math.PI);

      if (angle > 5) result[i] = 2;
      else if (angle > 2) result[i] = 1;
      else if (angle > -2) result[i] = 0;
      else if (angle > -5) result[i] = -1;
      else result[i] = -2;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("chop-zone", timestamps, [result]);
}
