import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, smaArray, stdDev as computeStdDev, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Stiffness — measures how often price stays above its lower Bollinger Band. */
export function stiffness(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const maPeriod = (params["maPeriod"] as number | undefined) ?? 100;
  const stiffPeriod = (params["stiffPeriod"] as number | undefined) ?? 60;
  const bbMult = (params["bbMult"] as number | undefined) ?? 2;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  const sma = smaArray(src, maPeriod);
  const sd = computeStdDev(src, maPeriod);

  const result = fillNaN(len);
  const startIdx = Math.max(maPeriod - 1, stiffPeriod - 1);

  for (let i = startIdx; i < len; i++) {
    let count = 0;
    for (let j = i - stiffPeriod + 1; j <= i; j++) {
      if (j >= maPeriod - 1 && !Number.isNaN(sma[j]!) && !Number.isNaN(sd[j]!)) {
        const lowerBand = sma[j]! - bbMult * sd[j]!;
        if (src[j]! > lowerBand) count++;
      }
    }
    result[i] = (count / stiffPeriod) * 100;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("stiffness", timestamps, [result]);
}
