import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** McGinley Dynamic — adaptive moving average that adjusts speed based on price action. */
export function mcginley(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("mcginley", timestamps, [result]);
  }

  result[0] = src[0]!;

  for (let i = 1; i < len; i++) {
    const prev = result[i - 1]!;
    const ratio = src[i]! / prev;
    const denominator = period * Math.pow(ratio, 4);
    result[i] = prev + (src[i]! - prev) / Math.max(denominator, 1e-10);
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("mcginley", timestamps, [result]);
}
