import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Money Flow Index — volume-weighted RSI. */
export function mfi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const len = data.length;
  const result = fillNaN(len);

  if (len < period + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("mfi", timestamps, [result]);
  }

  const tp = new Array<number>(len);
  const rawMF = new Array<number>(len);

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    tp[i] = (bar.high + bar.low + bar.close) / 3;
    rawMF[i] = tp[i]! * bar.volume;
  }

  for (let i = period; i < len; i++) {
    let posMF = 0;
    let negMF = 0;

    for (let j = i - period + 1; j <= i; j++) {
      if (tp[j]! > tp[j - 1]!) {
        posMF += rawMF[j]!;
      } else if (tp[j]! < tp[j - 1]!) {
        negMF += rawMF[j]!;
      }
    }

    result[i] = negMF === 0 ? 100 : 100 - 100 / (1 + posMF / negMF);
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("mfi", timestamps, [result]);
}
