import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** OHLC Volatility (Rogers-Satchell estimator). */
export function volOhlc(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const annualFactor = (params["annualFactor"] as number | undefined) ?? 365;

  const len = data.length;
  const result = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("vol-ohlc", timestamps, [result]);
  }

  const rs = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    if (bar.open > 0 && bar.close > 0 && bar.high > 0 && bar.low > 0) {
      const lnHC = Math.log(bar.high / bar.close);
      const lnHO = Math.log(bar.high / bar.open);
      const lnLC = Math.log(bar.low / bar.close);
      const lnLO = Math.log(bar.low / bar.open);
      rs[i] = lnHC * lnHO + lnLC * lnLO;
    } else {
      rs[i] = 0;
    }
  }

  for (let i = period - 1; i < len; i++) {
    let sum = 0;
    for (let j = i - period + 1; j <= i; j++) {
      sum += rs[j]!;
    }
    const variance = sum / period;
    result[i] = Math.sqrt(Math.max(0, variance) * annualFactor) * 100;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vol-ohlc", timestamps, [result]);
}
