import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, smaArray } from "../utils";

/** Hash Rate — proxy using volume as hash rate analog with SMA smoothing. */
export function hashRate(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;

  const len = data.length;
  const volumes = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    volumes[i] = data[i]!.volume;
  }

  const smoothed = smaArray(volumes, period);
  const timestamps = extractTimestamps(data);
  return buildOutput("hash-rate", timestamps, [smoothed]);
}
