import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { trueRange as computeTR, wilderSmooth, extractTimestamps, buildOutput, fillNaN, rollingMax, rollingMin } from "../utils";

/** Chande Kroll Stop — volatility-based trailing stop. */
export function chandeKrollStop(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const atrPeriod = (params["atrPeriod"] as number | undefined) ?? 10;
  const atrMult = (params["atrMult"] as number | undefined) ?? 1;
  const stopPeriod = (params["stopPeriod"] as number | undefined) ?? 9;

  const len = data.length;
  const tr = computeTR(data);
  const atrValues = wilderSmooth(tr, atrPeriod);

  const firstHighStop = fillNaN(len);
  const firstLowStop = fillNaN(len);

  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(atrValues[i]!)) {
      firstHighStop[i] = data[i]!.high - atrMult * atrValues[i]!;
      firstLowStop[i] = data[i]!.low + atrMult * atrValues[i]!;
    }
  }

  const stopShort = rollingMax(firstHighStop, stopPeriod);
  const stopLong = rollingMin(firstLowStop, stopPeriod);

  const timestamps = extractTimestamps(data);
  return buildOutput("chande-kroll-stop", timestamps, [stopShort, stopLong]);
}
