import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Ratio — close/open ratio per bar (measures intra-bar direction strength). */
export function ratio(
  data: OHLCV[],
  _params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const len = data.length;
  const result = new Array<number>(len);

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    result[i] = bar.open === 0 ? 1 : bar.close / bar.open;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("ratio", timestamps, [result]);
}
