import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Chaikin Volatility — rate of change of EMA of H-L range. */
export function chaikinVol(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const emaPeriod = (params["emaPeriod"] as number | undefined) ?? 10;
  const rocPeriod = (params["rocPeriod"] as number | undefined) ?? 10;

  const len = data.length;
  const hlDiff = new Array<number>(len);

  for (let i = 0; i < len; i++) {
    hlDiff[i] = data[i]!.high - data[i]!.low;
  }

  const emaHL = emaArray(hlDiff, emaPeriod);

  const result = fillNaN(len);
  for (let i = emaPeriod - 1 + rocPeriod; i < len; i++) {
    if (!Number.isNaN(emaHL[i]!) && !Number.isNaN(emaHL[i - rocPeriod]!) && emaHL[i - rocPeriod]! !== 0) {
      result[i] = ((emaHL[i]! - emaHL[i - rocPeriod]!) / emaHL[i - rocPeriod]!) * 100;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("chaikin-vol", timestamps, [result]);
}
