import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Auto Fibonacci Extension — finds swing points and plots extension levels. */
export function autoFibExt(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const lookback = (params["lookback"] as number | undefined) ?? 100;
  const len = data.length;

  const l1000 = fillNaN(len); // 100%
  const l1272 = fillNaN(len); // 127.2%
  const l1618 = fillNaN(len); // 161.8%
  const l2000 = fillNaN(len); // 200%
  const l2618 = fillNaN(len); // 261.8%

  const period = Math.min(lookback, len);
  if (period < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("auto-fib-ext", timestamps, [l1000, l1272, l1618, l2000, l2618]);
  }

  for (let i = period - 1; i < len; i++) {
    let swingHigh = -Infinity;
    let swingLow = Infinity;
    const start = Math.max(0, i - period + 1);

    for (let j = start; j <= i; j++) {
      if (data[j]!.high > swingHigh) swingHigh = data[j]!.high;
      if (data[j]!.low < swingLow) swingLow = data[j]!.low;
    }

    const range = swingHigh - swingLow;
    const uptrend = data[i]!.close > (swingHigh + swingLow) / 2;

    if (uptrend) {
      l1000[i] = swingHigh;
      l1272[i] = swingLow + range * 1.272;
      l1618[i] = swingLow + range * 1.618;
      l2000[i] = swingLow + range * 2.0;
      l2618[i] = swingLow + range * 2.618;
    } else {
      l1000[i] = swingLow;
      l1272[i] = swingHigh - range * 1.272;
      l1618[i] = swingHigh - range * 1.618;
      l2000[i] = swingHigh - range * 2.0;
      l2618[i] = swingHigh - range * 2.618;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("auto-fib-ext", timestamps, [l1000, l1272, l1618, l2000, l2618]);
}
