import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Price Channel — highest high and lowest low over period. */
export function priceChannel(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const len = data.length;

  const upper = fillNaN(len);
  const lower = fillNaN(len);
  const middle = fillNaN(len);

  for (let i = period - 1; i < len; i++) {
    let hh = -Infinity;
    let ll = Infinity;
    for (let j = i - period + 1; j <= i; j++) {
      if (data[j]!.high > hh) hh = data[j]!.high;
      if (data[j]!.low < ll) ll = data[j]!.low;
    }
    upper[i] = hh;
    lower[i] = ll;
    middle[i] = (hh + ll) / 2;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("price-channel", timestamps, [upper, middle, lower]);
}
