import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, smaArray, stdDev as computeStdDev, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Standard Error Bands — bands based on standard error of regression. */
export function stdErrBands(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const mult = (params["mult"] as number | undefined) ?? 2;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  const middle = smaArray(src, period);
  const sd = computeStdDev(src, period);
  const sqrtN = Math.sqrt(period);

  const upper = fillNaN(len);
  const lower = fillNaN(len);

  for (let i = period - 1; i < len; i++) {
    if (!Number.isNaN(middle[i]!) && !Number.isNaN(sd[i]!)) {
      const se = sd[i]! / sqrtN;
      upper[i] = middle[i]! + mult * se;
      lower[i] = middle[i]! - mult * se;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("std-err-bands", timestamps, [upper, middle, lower]);
}
