import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, emaArray, fillNaN } from "../utils";

/**
 * Funding Rate Indicator — approximates funding rate from price action.
 * Uses close-open spread relative to volume as a proxy for leveraged pressure.
 */
export function fundingRateIndicator(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 8;
  const len = data.length;

  const rawFunding = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const mid = (bar.high + bar.low) / 2;
    rawFunding[i] = mid === 0 ? 0 : (bar.close - mid) / mid;
  }

  const smoothed = emaArray(rawFunding, period);
  const timestamps = extractTimestamps(data);
  return buildOutput("funding-rate-indicator", timestamps, [smoothed]);
}
