import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Random Walk Index — measures trend strength vs random walk. */
export function rwi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const len = data.length;

  const rwiHigh = fillNaN(len);
  const rwiLow = fillNaN(len);

  if (len < period + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("rwi", timestamps, [rwiHigh, rwiLow]);
  }

  for (let i = period; i < len; i++) {
    let maxRwiH = 0;
    let maxRwiL = 0;

    for (let n = 2; n <= period; n++) {
      let atrSum = 0;
      for (let j = i - n + 1; j <= i; j++) {
        const bar = data[j]!;
        const prev = data[j - 1]!;
        const tr = Math.max(bar.high - bar.low, Math.abs(bar.high - prev.close), Math.abs(bar.low - prev.close));
        atrSum += tr;
      }
      const avgTR = atrSum / n;
      const denominator = avgTR * Math.sqrt(n);

      if (denominator > 0) {
        const rwiH = (data[i]!.high - data[i - n]!.low) / denominator;
        const rwiL = (data[i - n]!.high - data[i]!.low) / denominator;
        if (rwiH > maxRwiH) maxRwiH = rwiH;
        if (rwiL > maxRwiL) maxRwiL = rwiL;
      }
    }

    rwiHigh[i] = maxRwiH;
    rwiLow[i] = maxRwiL;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("rwi", timestamps, [rwiHigh, rwiLow]);
}
