import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Relative Vigor Index — measures conviction of a recent price action using OHLC symmetry. */
export function rvi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 10;
  const len = data.length;

  if (len < period + 3) {
    const timestamps = extractTimestamps(data);
    return buildOutput("rvi", timestamps, [fillNaN(len), fillNaN(len)]);
  }

  const numerator = new Array<number>(len);
  const denominator = new Array<number>(len);

  for (let i = 0; i < 3; i++) {
    numerator[i] = 0;
    denominator[i] = 0;
  }

  for (let i = 3; i < len; i++) {
    const bar = data[i]!;
    const bar1 = data[i - 1]!;
    const bar2 = data[i - 2]!;
    const bar3 = data[i - 3]!;

    numerator[i] = ((bar.close - bar.open) + 2 * (bar1.close - bar1.open) +
                    2 * (bar2.close - bar2.open) + (bar3.close - bar3.open)) / 6;
    denominator[i] = ((bar.high - bar.low) + 2 * (bar1.high - bar1.low) +
                      2 * (bar2.high - bar2.low) + (bar3.high - bar3.low)) / 6;
  }

  const rviLine = fillNaN(len);
  const signalLine = fillNaN(len);

  for (let i = period + 2; i < len; i++) {
    let numSum = 0;
    let denSum = 0;
    for (let j = i - period + 1; j <= i; j++) {
      numSum += numerator[j]!;
      denSum += denominator[j]!;
    }
    rviLine[i] = denSum === 0 ? 0 : numSum / denSum;
  }

  for (let i = period + 5; i < len; i++) {
    signalLine[i] = (rviLine[i]! + 2 * rviLine[i - 1]! + 2 * rviLine[i - 2]! + rviLine[i - 3]!) / 6;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("rvi", timestamps, [rviLine, signalLine]);
}
