import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** SMI Ergodic Oscillator — smoothed True Strength Index variant. */
export function smiErgodic(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const longPeriod = (params["longPeriod"] as number | undefined) ?? 20;
  const shortPeriod = (params["shortPeriod"] as number | undefined) ?? 5;
  const signalPeriod = (params["signalPeriod"] as number | undefined) ?? 5;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  if (len < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("smi-ergodic", timestamps, [fillNaN(len), fillNaN(len)]);
  }

  const change = new Array<number>(len);
  const absChange = new Array<number>(len);
  change[0] = 0;
  absChange[0] = 0;

  for (let i = 1; i < len; i++) {
    change[i] = src[i]! - src[i - 1]!;
    absChange[i] = Math.abs(change[i]!);
  }

  const smoothChange1 = emaArray(change, longPeriod);
  const validSC1 = smoothChange1.filter((v) => !Number.isNaN(v));
  const smoothChange2 = emaArray(validSC1, shortPeriod);

  const smoothAbs1 = emaArray(absChange, longPeriod);
  const validSA1 = smoothAbs1.filter((v) => !Number.isNaN(v));
  const smoothAbs2 = emaArray(validSA1, shortPeriod);

  const smiLine = fillNaN(len);
  const offset = longPeriod - 1 + shortPeriod - 1;

  for (let i = 0; i < smoothChange2.length; i++) {
    const idx = offset + i;
    if (idx < len && !Number.isNaN(smoothChange2[i]!) && !Number.isNaN(smoothAbs2[i]!)) {
      smiLine[idx] = smoothAbs2[i]! === 0 ? 0 : (smoothChange2[i]! / smoothAbs2[i]!) * 100;
    }
  }

  const validSmi = smiLine.filter((v) => !Number.isNaN(v));
  const signalValues = emaArray(validSmi, signalPeriod);
  const signalLine = fillNaN(len);

  let sigIdx = 0;
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(smiLine[i]!)) {
      if (sigIdx < signalValues.length && !Number.isNaN(signalValues[sigIdx]!)) {
        signalLine[i] = signalValues[sigIdx]!;
      }
      sigIdx++;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("smi-ergodic", timestamps, [smiLine, signalLine]);
}
