import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { trueRange as computeTR, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Choppiness Index — measures whether market is trending or ranging. */
export function chopIdx(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const len = data.length;
  const result = fillNaN(len);

  if (len < period + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("chop-idx", timestamps, [result]);
  }

  const tr = computeTR(data);

  for (let i = period; i < len; i++) {
    let trSum = 0;
    let hh = -Infinity;
    let ll = Infinity;

    for (let j = i - period + 1; j <= i; j++) {
      trSum += tr[j]!;
      if (data[j]!.high > hh) hh = data[j]!.high;
      if (data[j]!.low < ll) ll = data[j]!.low;
    }

    const hlRange = hh - ll;
    if (hlRange > 0 && trSum > 0) {
      result[i] = (100 * Math.log10(trSum / hlRange)) / Math.log10(period);
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("chop-idx", timestamps, [result]);
}
