import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Williams %R. */
export function williamsR(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const len = data.length;
  const result = fillNaN(len);

  for (let i = period - 1; i < len; i++) {
    let hh = -Infinity;
    let ll = Infinity;
    for (let j = i - period + 1; j <= i; j++) {
      if (data[j]!.high > hh) hh = data[j]!.high;
      if (data[j]!.low < ll) ll = data[j]!.low;
    }
    const range = hh - ll;
    result[i] = range === 0 ? -50 : ((hh - data[i]!.close) / range) * -100;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("williams-r", timestamps, [result]);
}
