import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/**
 * Volume Profile Fixed Range — computes volume distribution across price levels
 * for the full data range. Returns volume per price row.
 */
export function vpfr(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const rows = (params["rows"] as number | undefined) ?? 24;
  const len = data.length;

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("vpfr", timestamps, [fillNaN(len)]);
  }

  let overallHigh = -Infinity;
  let overallLow = Infinity;

  for (let i = 0; i < len; i++) {
    if (data[i]!.high > overallHigh) overallHigh = data[i]!.high;
    if (data[i]!.low < overallLow) overallLow = data[i]!.low;
  }

  const range = overallHigh - overallLow;
  if (range === 0) {
    const result = new Array<number>(len);
    for (let i = 0; i < len; i++) result[i] = data[i]!.volume;
    const timestamps = extractTimestamps(data);
    return buildOutput("vpfr", timestamps, [result]);
  }

  const rowSize = range / rows;
  const volumeByRow = new Array<number>(rows).fill(0);

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const lowRow = Math.max(0, Math.floor((bar.low - overallLow) / rowSize));
    const highRow = Math.min(rows - 1, Math.floor((bar.high - overallLow) / rowSize));
    const barsInRange = highRow - lowRow + 1;
    const volPerRow = bar.volume / barsInRange;

    for (let r = lowRow; r <= highRow; r++) {
      volumeByRow[r] = volumeByRow[r]! + volPerRow;
    }
  }

  const result = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const midPrice = (bar.high + bar.low) / 2;
    const row = Math.min(rows - 1, Math.max(0, Math.floor((midPrice - overallLow) / rowSize)));
    result[i] = volumeByRow[row]!;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vpfr", timestamps, [result]);
}
