import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Auto Trendlines — detects significant pivot points and draws trendlines. */
export function autoTrendlines(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const pivotStrength = (params["pivotStrength"] as number | undefined) ?? 5;
  const len = data.length;

  const supportLine = fillNaN(len);
  const resistanceLine = fillNaN(len);

  if (len < pivotStrength * 2 + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("auto-trendlines", timestamps, [supportLine, resistanceLine]);
  }

  const pivotHighs: Array<{ idx: number; price: number }> = [];
  const pivotLows: Array<{ idx: number; price: number }> = [];

  for (let i = pivotStrength; i < len - pivotStrength; i++) {
    let isHigh = true;
    let isLow = true;

    for (let j = 1; j <= pivotStrength; j++) {
      if (data[i]!.high <= data[i - j]!.high || data[i]!.high <= data[i + j]!.high) isHigh = false;
      if (data[i]!.low >= data[i - j]!.low || data[i]!.low >= data[i + j]!.low) isLow = false;
    }

    if (isHigh) pivotHighs.push({ idx: i, price: data[i]!.high });
    if (isLow) pivotLows.push({ idx: i, price: data[i]!.low });
  }

  if (pivotHighs.length >= 2) {
    const p1 = pivotHighs[pivotHighs.length - 2]!;
    const p2 = pivotHighs[pivotHighs.length - 1]!;
    const slope = (p2.price - p1.price) / (p2.idx - p1.idx);

    for (let i = p1.idx; i < len; i++) {
      resistanceLine[i] = p1.price + slope * (i - p1.idx);
    }
  }

  if (pivotLows.length >= 2) {
    const p1 = pivotLows[pivotLows.length - 2]!;
    const p2 = pivotLows[pivotLows.length - 1]!;
    const slope = (p2.price - p1.price) / (p2.idx - p1.idx);

    for (let i = p1.idx; i < len; i++) {
      supportLine[i] = p1.price + slope * (i - p1.idx);
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("auto-trendlines", timestamps, [supportLine, resistanceLine]);
}
