import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { awesomeOscillator } from "./awesome-oscillator";

/** AO — Accelerator Oscillator. Alias for Awesome Oscillator with standard params. */
export function ao(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = awesomeOscillator(data, params);
  return { indicatorId: "ao", data: result.data };
}
