import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput } from "../utils";

/** Net Volume — positive when bullish (close > open), negative when bearish. */
export function netVolume(
  data: OHLCV[],
  _params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const len = data.length;
  const result = new Array<number>(len);

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    result[i] = bar.close >= bar.open ? bar.volume : -bar.volume;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("net-volume", timestamps, [result]);
}
