import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { trueRange as computeTR, wilderSmooth, extractTimestamps, buildOutput } from "../utils";

/** Average True Range. */
export function atr(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;

  const tr = computeTR(data);
  const result = wilderSmooth(tr, period);

  const timestamps = extractTimestamps(data);
  return buildOutput("atr", timestamps, [result]);
}
