import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { fisherTransform } from "../oscillators/fisher-transform";

/** Ehlers Fisher Transform — alias for Fisher Transform. */
export function ehlersFisher(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = fisherTransform(data, params);
  return { indicatorId: "ehlers-fisher", data: result.data };
}
