import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, smaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** KST — Know Sure Thing oscillator. */
export function kst(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const roc1 = (params["roc1"] as number | undefined) ?? 10;
  const roc2 = (params["roc2"] as number | undefined) ?? 15;
  const roc3 = (params["roc3"] as number | undefined) ?? 20;
  const roc4 = (params["roc4"] as number | undefined) ?? 30;
  const sma1 = (params["sma1"] as number | undefined) ?? 10;
  const sma2 = (params["sma2"] as number | undefined) ?? 10;
  const sma3 = (params["sma3"] as number | undefined) ?? 10;
  const sma4 = (params["sma4"] as number | undefined) ?? 15;
  const signalPeriod = (params["signalPeriod"] as number | undefined) ?? 9;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  const computeROC = (period: number): number[] => {
    const r = fillNaN(len);
    for (let i = period; i < len; i++) {
      const prev = src[i - period]!;
      r[i] = prev === 0 ? 0 : ((src[i]! - prev) / prev) * 100;
    }
    return r;
  };

  const rocValues1 = computeROC(roc1);
  const rocValues2 = computeROC(roc2);
  const rocValues3 = computeROC(roc3);
  const rocValues4 = computeROC(roc4);

  const smaROC1 = smaArray(rocValues1.filter((v) => !Number.isNaN(v)), sma1);
  const smaROC2 = smaArray(rocValues2.filter((v) => !Number.isNaN(v)), sma2);
  const smaROC3 = smaArray(rocValues3.filter((v) => !Number.isNaN(v)), sma3);
  const smaROC4 = smaArray(rocValues4.filter((v) => !Number.isNaN(v)), sma4);

  const kstLine = fillNaN(len);
  const maxOffset = roc4 + sma4 - 1;

  for (let i = maxOffset; i < len; i++) {
    const i1 = i - roc1 - (sma1 - 1);
    const i2 = i - roc2 - (sma2 - 1);
    const i3 = i - roc3 - (sma3 - 1);
    const i4 = i - roc4 - (sma4 - 1);

    if (i1 >= 0 && i1 < smaROC1.length && !Number.isNaN(smaROC1[i1]!) &&
        i2 >= 0 && i2 < smaROC2.length && !Number.isNaN(smaROC2[i2]!) &&
        i3 >= 0 && i3 < smaROC3.length && !Number.isNaN(smaROC3[i3]!) &&
        i4 >= 0 && i4 < smaROC4.length && !Number.isNaN(smaROC4[i4]!)) {
      kstLine[i] = smaROC1[i1]! * 1 + smaROC2[i2]! * 2 + smaROC3[i3]! * 3 + smaROC4[i4]! * 4;
    }
  }

  const validKst = kstLine.filter((v) => !Number.isNaN(v));
  const signalValues = smaArray(validKst, signalPeriod);

  const signalLine = fillNaN(len);
  let sigIdx = 0;
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(kstLine[i]!)) {
      if (sigIdx < signalValues.length && !Number.isNaN(signalValues[sigIdx]!)) {
        signalLine[i] = signalValues[sigIdx]!;
      }
      sigIdx++;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("kst", timestamps, [kstLine, signalLine]);
}
