import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN, smaArray } from "../utils";

/** Awesome Oscillator — difference between 5-period and 34-period SMA of median price. */
export function awesomeOscillator(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const fastPeriod = (params["fastPeriod"] as number | undefined) ?? 5;
  const slowPeriod = (params["slowPeriod"] as number | undefined) ?? 34;

  const len = data.length;
  const medianPrice = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    medianPrice[i] = (data[i]!.high + data[i]!.low) / 2;
  }

  const fastSma = smaArray(medianPrice, fastPeriod);
  const slowSma = smaArray(medianPrice, slowPeriod);

  const result = fillNaN(len);
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(fastSma[i]!) && !Number.isNaN(slowSma[i]!)) {
      result[i] = fastSma[i]! - slowSma[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("awesome-oscillator", timestamps, [result]);
}
