import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { wilderSmooth, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Average Directional Index. */
export function adx(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const len = data.length;

  if (len < period + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("adx", timestamps, [fillNaN(len), fillNaN(len), fillNaN(len)]);
  }

  const plusDM = new Array<number>(len);
  const minusDM = new Array<number>(len);
  const tr = new Array<number>(len);

  plusDM[0] = 0;
  minusDM[0] = 0;
  tr[0] = data[0]!.high - data[0]!.low;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const prevBar = data[i - 1]!;

    const upMove = bar.high - prevBar.high;
    const downMove = prevBar.low - bar.low;

    plusDM[i] = upMove > downMove && upMove > 0 ? upMove : 0;
    minusDM[i] = downMove > upMove && downMove > 0 ? downMove : 0;

    const hl = bar.high - bar.low;
    const hc = Math.abs(bar.high - prevBar.close);
    const lc = Math.abs(bar.low - prevBar.close);
    tr[i] = Math.max(hl, hc, lc);
  }

  const smoothPlusDM = wilderSmooth(plusDM, period);
  const smoothMinusDM = wilderSmooth(minusDM, period);
  const smoothTR = wilderSmooth(tr, period);

  const plusDI = fillNaN(len);
  const minusDI = fillNaN(len);
  const dx = fillNaN(len);

  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(smoothTR[i]!) && smoothTR[i]! !== 0) {
      plusDI[i] = (smoothPlusDM[i]! / smoothTR[i]!) * 100;
      minusDI[i] = (smoothMinusDM[i]! / smoothTR[i]!) * 100;

      const diSum = plusDI[i]! + minusDI[i]!;
      dx[i] = diSum === 0 ? 0 : (Math.abs(plusDI[i]! - minusDI[i]!) / diSum) * 100;
    }
  }

  const validDx = dx.filter((v) => !Number.isNaN(v));
  const adxValues = wilderSmooth(validDx, period);

  const adxLine = fillNaN(len);
  let adxIdx = 0;
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(dx[i]!)) {
      if (adxIdx < adxValues.length && !Number.isNaN(adxValues[adxIdx]!)) {
        adxLine[i] = adxValues[adxIdx]!;
      }
      adxIdx++;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("adx", timestamps, [adxLine, plusDI, minusDI]);
}
