import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { trueRange as computeTR, wilderSmooth, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Supertrend — ATR-based trend following indicator. */
export function supertrend(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 10;
  const mult = (params["mult"] as number | undefined) ?? 3;

  const len = data.length;
  const tr = computeTR(data);
  const atrValues = wilderSmooth(tr, period);

  const superLine = fillNaN(len);
  const direction = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("supertrend", timestamps, [superLine, direction]);
  }

  const upperBand = fillNaN(len);
  const lowerBand = fillNaN(len);

  for (let i = period - 1; i < len; i++) {
    if (Number.isNaN(atrValues[i]!)) continue;

    const hl2 = (data[i]!.high + data[i]!.low) / 2;
    upperBand[i] = hl2 + mult * atrValues[i]!;
    lowerBand[i] = hl2 - mult * atrValues[i]!;
  }

  let prevUpperBand = upperBand[period - 1]!;
  let prevLowerBand = lowerBand[period - 1]!;
  let prevSupertrend = upperBand[period - 1]!;
  let prevDir = -1;

  superLine[period - 1] = prevSupertrend;
  direction[period - 1] = prevDir;

  for (let i = period; i < len; i++) {
    if (Number.isNaN(upperBand[i]!) || Number.isNaN(lowerBand[i]!)) continue;

    const currentUpper = upperBand[i]!;
    const currentLower = lowerBand[i]!;
    const prevClose = data[i - 1]!.close;

    const finalUpper = (currentUpper < prevUpperBand || prevClose > prevUpperBand)
      ? currentUpper : prevUpperBand;
    const finalLower = (currentLower > prevLowerBand || prevClose < prevLowerBand)
      ? currentLower : prevLowerBand;

    let dir: number;
    if (prevSupertrend === prevUpperBand) {
      dir = data[i]!.close > finalUpper ? 1 : -1;
    } else {
      dir = data[i]!.close < finalLower ? -1 : 1;
    }

    superLine[i] = dir === 1 ? finalLower : finalUpper;
    direction[i] = dir;

    prevUpperBand = finalUpper;
    prevLowerBand = finalLower;
    prevSupertrend = superLine[i]!;
    prevDir = dir;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("supertrend", timestamps, [superLine, direction]);
}
