import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { vwRsi } from "./vw-rsi";

/** Volume Weighted RSI — alias for VW-RSI. */
export function volumeWeightedRsi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = vwRsi(data, params);
  return { indicatorId: "volume-weighted-rsi", data: result.data };
}
