import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Accumulative Swing Index. */
export function asi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const limitMove = (params["limitMove"] as number | undefined) ?? 1000;
  const len = data.length;
  const result = fillNaN(len);

  if (len < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("asi", timestamps, [result]);
  }

  result[0] = 0;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const prev = data[i - 1]!;

    const k = Math.max(
      Math.abs(bar.high - prev.close),
      Math.abs(bar.low - prev.close),
    );

    const trVal = Math.max(
      Math.abs(bar.high - prev.close),
      Math.abs(bar.low - prev.close),
      Math.abs(bar.high - bar.low),
    );

    if (trVal === 0) {
      result[i] = result[i - 1]!;
      continue;
    }

    const er = Math.abs(bar.high - prev.close) >= Math.abs(bar.low - prev.close)
      ? Math.abs(bar.high - prev.close) - Math.abs(bar.low - prev.close) / 2 + Math.abs(prev.close - prev.open) / 4
      : Math.abs(bar.low - prev.close) - Math.abs(bar.high - prev.close) / 2 + Math.abs(prev.close - prev.open) / 4;

    const sh = Math.abs(prev.close - prev.open);
    const r = trVal - sh / 2 + sh / 4;

    if (r === 0) {
      result[i] = result[i - 1]!;
      continue;
    }

    const si = (50 * (bar.close - prev.close + (bar.close - bar.open) / 2 + (prev.close - prev.open) / 2) / r) * (k / limitMove);
    result[i] = result[i - 1]! + si;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("asi", timestamps, [result]);
}
