import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Correlation (Log) — Pearson correlation using log prices. */
export function correlationLog(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("correlation-log", timestamps, [result]);
  }

  for (let i = period - 1; i < len; i++) {
    let sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0, sumY2 = 0;

    for (let j = 0; j < period; j++) {
      const x = j;
      const price = src[i - period + 1 + j]!;
      const y = price > 0 ? Math.log(price) : 0;
      sumX += x;
      sumY += y;
      sumXY += x * y;
      sumX2 += x * x;
      sumY2 += y * y;
    }

    const numerator = period * sumXY - sumX * sumY;
    const denominator = Math.sqrt((period * sumX2 - sumX * sumX) * (period * sumY2 - sumY * sumY));
    result[i] = denominator === 0 ? 0 : numerator / denominator;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("correlation-log", timestamps, [result]);
}
