import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput } from "../utils";

/**
 * VWAP — Volume Weighted Average Price (cumulative, resets at session start).
 *
 * @param sessionStartHour - UTC hour at which the session resets (0-23).
 *   Default 0 (UTC midnight) — suitable for 24/7 crypto markets.
 *   Set to 23 for CME futures (17:00 CT = 23:00 UTC), etc.
 * @param resetMode - "daily" resets each session day, "never" runs cumulative
 *   across the entire dataset (useful for anchored VWAP).
 */
export function vwap(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const sessionStartHour = (params["sessionStartHour"] as number | undefined) ?? 0;
  const resetMode = (params["resetMode"] as string | undefined) ?? "daily";

  const len = data.length;
  const result = new Array<number>(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("vwap", timestamps, [result]);
  }

  let cumTPV = 0;
  let cumVol = 0;
  let lastSessionId = -1;

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;

    if (resetMode === "daily") {
      const sessionId = getSessionId(bar.timestamp, sessionStartHour);
      if (sessionId !== lastSessionId) {
        cumTPV = 0;
        cumVol = 0;
        lastSessionId = sessionId;
      }
    }

    const tp = (bar.high + bar.low + bar.close) / 3;
    cumTPV += tp * bar.volume;
    cumVol += bar.volume;

    result[i] = cumVol === 0 ? tp : cumTPV / cumVol;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vwap", timestamps, [result]);
}

/**
 * Compute a unique session identifier for a timestamp given a session start hour.
 * The session day flips at `sessionStartHour` UTC, not at midnight.
 * For example, with sessionStartHour=23, timestamps from 23:00 UTC on day N
 * through 22:59 UTC on day N+1 all belong to the same session.
 */
function getSessionId(timestamp: number, sessionStartHour: number): number {
  const adjustedMs = timestamp - sessionStartHour * 3_600_000;
  const date = new Date(adjustedMs);
  return date.getUTCFullYear() * 10000 + date.getUTCMonth() * 100 + date.getUTCDate();
}
