import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** FRAMA — Fractal Adaptive Moving Average. */
export function frama(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 16;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  const halfPeriod = Math.max(2, Math.floor(period / 2));
  const lookback = halfPeriod * 2;

  if (len < lookback) {
    const timestamps = extractTimestamps(data);
    return buildOutput("frama", timestamps, [result]);
  }

  result[lookback - 1] = src[lookback - 1]!;

  for (let i = lookback; i < len; i++) {
    const start = i - lookback + 1;
    const mid = start + halfPeriod;

    let hh1 = -Infinity, ll1 = Infinity;
    for (let j = start; j < mid; j++) {
      if (src[j]! > hh1) hh1 = src[j]!;
      if (src[j]! < ll1) ll1 = src[j]!;
    }
    const n1 = (hh1 - ll1) / halfPeriod;

    let hh2 = -Infinity, ll2 = Infinity;
    for (let j = mid; j <= i; j++) {
      if (src[j]! > hh2) hh2 = src[j]!;
      if (src[j]! < ll2) ll2 = src[j]!;
    }
    const n2 = (hh2 - ll2) / halfPeriod;

    let hh3 = -Infinity, ll3 = Infinity;
    for (let j = start; j <= i; j++) {
      if (src[j]! > hh3) hh3 = src[j]!;
      if (src[j]! < ll3) ll3 = src[j]!;
    }
    const n3 = (hh3 - ll3) / lookback;

    let dimension = 1;
    if (n1 > 0 && n2 > 0 && n3 > 0) {
      dimension = (Math.log(n1 + n2) - Math.log(n3)) / Math.log(2);
    }

    const alpha = Math.max(0.01, Math.min(1, Math.exp(-4.6 * (dimension - 1))));
    result[i] = alpha * src[i]! + (1 - alpha) * result[i - 1]!;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("frama", timestamps, [result]);
}
