import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Zero-Trend Close-to-Close Volatility — assumes zero mean return. */
export function volZtcc(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const annualFactor = (params["annualFactor"] as number | undefined) ?? 365;

  const len = data.length;
  const result = fillNaN(len);

  if (len < period + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("vol-ztcc", timestamps, [result]);
  }

  const logRetSq = fillNaN(len);
  for (let i = 1; i < len; i++) {
    if (data[i - 1]!.close > 0 && data[i]!.close > 0) {
      const lr = Math.log(data[i]!.close / data[i - 1]!.close);
      logRetSq[i] = lr * lr;
    }
  }

  for (let i = period; i < len; i++) {
    let sum = 0;
    let count = 0;
    for (let j = i - period + 1; j <= i; j++) {
      if (!Number.isNaN(logRetSq[j]!)) {
        sum += logRetSq[j]!;
        count++;
      }
    }
    if (count > 0) {
      result[i] = Math.sqrt((sum / count) * annualFactor) * 100;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vol-ztcc", timestamps, [result]);
}
