import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** TRIX — triple-smoothed EMA rate of change. */
export function trix(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 15;
  const signalPeriod = (params["signalPeriod"] as number | undefined) ?? 9;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;

  const e1 = emaArray(src, period);
  const e1v = e1.filter((v) => !Number.isNaN(v));
  const e2 = emaArray(e1v, period);
  const e2v = e2.filter((v) => !Number.isNaN(v));
  const e3 = emaArray(e2v, period);

  const trixLine = fillNaN(len);
  const offset = (period - 1) * 3;

  for (let i = 1; i < e3.length; i++) {
    if (!Number.isNaN(e3[i]!) && !Number.isNaN(e3[i - 1]!) && e3[i - 1]! !== 0) {
      const idx = offset + i;
      if (idx < len) {
        trixLine[idx] = ((e3[i]! - e3[i - 1]!) / e3[i - 1]!) * 10000;
      }
    }
  }

  const validTrix = trixLine.filter((v) => !Number.isNaN(v));
  const signalValues = emaArray(validTrix, signalPeriod);
  const signalLine = fillNaN(len);

  let sigIdx = 0;
  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(trixLine[i]!)) {
      if (sigIdx < signalValues.length && !Number.isNaN(signalValues[sigIdx]!)) {
        signalLine[i] = signalValues[sigIdx]!;
      }
      sigIdx++;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("trix", timestamps, [trixLine, signalLine]);
}
