import type { OHLCV } from "@deskmodal/core";

/** A single row in the volume profile histogram. */
export interface VolumeProfileRow {
  /** Center price of this row. */
  priceLevel: number;
  /** Total volume traded at this price level. */
  totalVolume: number;
  /** Volume from bullish bars (close > open). */
  buyVolume: number;
  /** Volume from bearish bars (close < open). */
  sellVolume: number;
}

/** Result of computing a volume profile over OHLCV data. */
export interface VolumeProfileResult {
  /** Volume histogram rows, ordered from lowest to highest price level. */
  rows: VolumeProfileRow[];
  /** Price level with the highest total volume (Point of Control). */
  pocPrice: number;
  /** Index of the POC row within the rows array. */
  pocIndex: number;
  /** Upper boundary of the Value Area. */
  vaHigh: number;
  /** Lower boundary of the Value Area. */
  vaLow: number;
  /** Sum of all volume across all rows. */
  totalVolume: number;
  /** Price distance each row spans. */
  rowHeight: number;
}

/** Parameters for volume profile computation. */
export interface VolumeProfileParams {
  /** Number of price rows (default 24). */
  rows?: number;
  /** Fraction of total volume for Value Area (default 0.70). */
  valueAreaPercent?: number;
  /** Start index into data array (inclusive). */
  startIndex?: number;
  /** End index into data array (exclusive). */
  endIndex?: number;
}

/**
 * Compute a volume profile from OHLCV data.
 *
 * Distributes each bar's volume across price rows proportional to the bar's
 * range overlap with each row. Buy/sell classification uses close vs open.
 * Value Area expands from POC alternately up/down, preferring the side with
 * more volume, until valueAreaPercent of total volume is enclosed.
 *
 * Pure function — no side effects.
 */
export function computeVolumeProfile(
  data: readonly OHLCV[],
  params?: VolumeProfileParams,
): VolumeProfileResult {
  const numRows = params?.rows ?? 24;
  const valueAreaPercent = params?.valueAreaPercent ?? 0.70;
  const startIdx = params?.startIndex ?? 0;
  const endIdx = params?.endIndex ?? data.length;

  const emptyResult: VolumeProfileResult = {
    rows: [],
    pocPrice: 0,
    pocIndex: 0,
    vaHigh: 0,
    vaLow: 0,
    totalVolume: 0,
    rowHeight: 0,
  };

  if (data.length === 0 || startIdx >= endIdx || numRows < 1) {
    return emptyResult;
  }

  // Find price range across the data slice
  let overallHigh = -Infinity;
  let overallLow = Infinity;

  for (let i = startIdx; i < endIdx; i++) {
    const bar = data[i]!;
    if (bar.high > overallHigh) overallHigh = bar.high;
    if (bar.low < overallLow) overallLow = bar.low;
  }

  const range = overallHigh - overallLow;
  if (range === 0 || !Number.isFinite(range)) {
    // All bars at the same price — single row with all volume
    let vol = 0;
    for (let i = startIdx; i < endIdx; i++) {
      vol += data[i]!.volume;
    }
    const row: VolumeProfileRow = {
      priceLevel: overallHigh,
      totalVolume: vol,
      buyVolume: 0,
      sellVolume: 0,
    };
    // Classify buy/sell
    for (let i = startIdx; i < endIdx; i++) {
      const bar = data[i]!;
      if (bar.close > bar.open) {
        row.buyVolume += bar.volume;
      } else if (bar.close < bar.open) {
        row.sellVolume += bar.volume;
      } else {
        // Neutral: split evenly
        row.buyVolume += bar.volume * 0.5;
        row.sellVolume += bar.volume * 0.5;
      }
    }
    return {
      rows: [row],
      pocPrice: overallHigh,
      pocIndex: 0,
      vaHigh: overallHigh,
      vaLow: overallHigh,
      totalVolume: vol,
      rowHeight: 0,
    };
  }

  const rowHeight = range / numRows;

  // Allocate row accumulators
  const totalVol = new Float64Array(numRows);
  const buyVol = new Float64Array(numRows);
  const sellVol = new Float64Array(numRows);

  let grandTotal = 0;

  // Distribute each bar's volume across rows proportional to overlap
  for (let i = startIdx; i < endIdx; i++) {
    const bar = data[i]!;
    const barVol = bar.volume;
    if (barVol <= 0) continue;

    grandTotal += barVol;

    const barLow = bar.low;
    const barHigh = bar.high;
    const barRange = barHigh - barLow;

    const isBuy = bar.close > bar.open;
    const isSell = bar.close < bar.open;

    if (barRange === 0) {
      // Point bar — assign to a single row
      const rowIdx = Math.min(numRows - 1, Math.max(0, Math.floor((barLow - overallLow) / rowHeight)));
      totalVol[rowIdx] = totalVol[rowIdx]! + barVol;
      if (isBuy) {
        buyVol[rowIdx] = buyVol[rowIdx]! + barVol;
      } else if (isSell) {
        sellVol[rowIdx] = sellVol[rowIdx]! + barVol;
      } else {
        buyVol[rowIdx] = buyVol[rowIdx]! + barVol * 0.5;
        sellVol[rowIdx] = sellVol[rowIdx]! + barVol * 0.5;
      }
      continue;
    }

    // Determine the row range this bar spans
    const lowRow = Math.max(0, Math.floor((barLow - overallLow) / rowHeight));
    const highRow = Math.min(numRows - 1, Math.floor((barHigh - overallLow) / rowHeight));

    for (let r = lowRow; r <= highRow; r++) {
      // Row boundaries in price space
      const rowBottom = overallLow + r * rowHeight;
      const rowTop = rowBottom + rowHeight;

      // Overlap between bar range and row range
      const overlapLow = Math.max(barLow, rowBottom);
      const overlapHigh = Math.min(barHigh, rowTop);
      const overlap = Math.max(0, overlapHigh - overlapLow);

      const fraction = overlap / barRange;
      const rowVolume = barVol * fraction;

      totalVol[r] = totalVol[r]! + rowVolume;
      if (isBuy) {
        buyVol[r] = buyVol[r]! + rowVolume;
      } else if (isSell) {
        sellVol[r] = sellVol[r]! + rowVolume;
      } else {
        buyVol[r] = buyVol[r]! + rowVolume * 0.5;
        sellVol[r] = sellVol[r]! + rowVolume * 0.5;
      }
    }
  }

  // Build rows array and find POC
  const rows: VolumeProfileRow[] = new Array(numRows);
  let pocIdx = 0;
  let maxVol = 0;

  for (let r = 0; r < numRows; r++) {
    const priceLevel = overallLow + (r + 0.5) * rowHeight;
    rows[r] = {
      priceLevel,
      totalVolume: totalVol[r]!,
      buyVolume: buyVol[r]!,
      sellVolume: sellVol[r]!,
    };
    if (totalVol[r]! > maxVol) {
      maxVol = totalVol[r]!;
      pocIdx = r;
    }
  }

  // Compute Value Area: expand from POC alternately up/down
  const vaTarget = grandTotal * valueAreaPercent;
  let vaVolume = totalVol[pocIdx]!;
  let vaLowIdx = pocIdx;
  let vaHighIdx = pocIdx;

  while (vaVolume < vaTarget && (vaLowIdx > 0 || vaHighIdx < numRows - 1)) {
    const nextLow = vaLowIdx > 0 ? totalVol[vaLowIdx - 1]! : -1;
    const nextHigh = vaHighIdx < numRows - 1 ? totalVol[vaHighIdx + 1]! : -1;

    if (nextLow < 0 && nextHigh < 0) break;

    if (nextLow >= nextHigh) {
      vaLowIdx--;
      vaVolume += totalVol[vaLowIdx]!;
    } else {
      vaHighIdx++;
      vaVolume += totalVol[vaHighIdx]!;
    }
  }

  const pocPrice = rows[pocIdx]!.priceLevel;
  const vaLow = overallLow + vaLowIdx * rowHeight;
  const vaHigh = overallLow + (vaHighIdx + 1) * rowHeight;

  return {
    rows,
    pocPrice,
    pocIndex: pocIdx,
    vaHigh,
    vaLow,
    totalVolume: grandTotal,
    rowHeight,
  };
}
