import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput } from "../utils";

/** Cumulative Volume Delta — estimates buying/selling pressure from OHLCV. */
export function cvd(
  data: OHLCV[],
  _params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const len = data.length;
  const result = new Array<number>(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("cvd", timestamps, [result]);
  }

  let cumDelta = 0;

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const range = bar.high - bar.low;

    let buyRatio: number;
    if (range === 0) {
      buyRatio = bar.close >= bar.open ? 1 : 0;
    } else {
      buyRatio = (bar.close - bar.low) / range;
    }

    const buyVolume = bar.volume * buyRatio;
    const sellVolume = bar.volume * (1 - buyRatio);
    const delta = buyVolume - sellVolume;

    cumDelta += delta;
    result[i] = cumDelta;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("cvd", timestamps, [result]);
}
