import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Elder Ray — bull power (high - EMA) and bear power (low - EMA). */
export function elderRay(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 13;
  const len = data.length;

  const closes = new Array<number>(len);
  for (let i = 0; i < len; i++) closes[i] = data[i]!.close;

  const emaValues = emaArray(closes, period);
  const bullPower = fillNaN(len);
  const bearPower = fillNaN(len);

  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(emaValues[i]!)) {
      bullPower[i] = data[i]!.high - emaValues[i]!;
      bearPower[i] = data[i]!.low - emaValues[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("elder-ray", timestamps, [bullPower, bearPower]);
}
