import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { alma } from "./alma";

/** Arnaud Legoux Moving Average — alias for ALMA. */
export function arnaudLegoux(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = alma(data, params);
  return { indicatorId: "arnaud-legoux", data: result.data };
}
