import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { williamsR } from "./williams-r";

/** Percent R — alias for Williams %R. */
export function percentR(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = williamsR(data, params);
  return { indicatorId: "percent-r", data: result.data };
}
