import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, emaArray, extractTimestamps, buildOutput } from "../utils";

/**
 * Moving Average Ribbon — multiple EMAs at increasing periods.
 * Default: 8 EMAs from period 20 to 55, step 5.
 */
export function maRibbon(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const startPeriod = (params["startPeriod"] as number | undefined) ?? 20;
  const endPeriod = (params["endPeriod"] as number | undefined) ?? 55;
  const step = (params["step"] as number | undefined) ?? 5;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const timestamps = extractTimestamps(data);

  const series: number[][] = [];
  for (let p = startPeriod; p <= endPeriod; p += step) {
    series.push(emaArray(src, p));
  }

  return buildOutput("ma-ribbon", timestamps, series);
}
