import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { dpo } from "./dpo";

/** Detrended Price — alias for DPO. */
export function detrendedPrice(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = dpo(data, params);
  return { indicatorId: "detrended-price", data: result.data };
}
