import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN, smaArray } from "../utils";

/** Commodity Channel Index. */
export function cci(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const len = data.length;
  const result = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("cci", timestamps, [result]);
  }

  const tp = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    tp[i] = (bar.high + bar.low + bar.close) / 3;
  }

  const tpSma = smaArray(tp, period);
  const constant = 0.015;

  for (let i = period - 1; i < len; i++) {
    const mean = tpSma[i]!;
    let meanDev = 0;
    for (let j = i - period + 1; j <= i; j++) {
      meanDev += Math.abs(tp[j]! - mean);
    }
    meanDev /= period;

    result[i] = meanDev === 0 ? 0 : (tp[i]! - mean) / (constant * meanDev);
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("cci", timestamps, [result]);
}
