class IndicatorRegistryImpl implements IndicatorRegistry {
  private readonly indicators = new Map<string, { metadata: IndicatorMetadata; compute: IndicatorFunction }>();

  register(metadata: IndicatorMetadata, compute: IndicatorFunction): void {
    this.indicators.set(metadata.id, { metadata, compute });
  }

  get(indicatorId: string): IndicatorFunction | undefined {
    return this.indicators.get(indicatorId)?.compute;
  }

  getMetadata(indicatorId: string): IndicatorMetadata | undefined {
    return this.indicators.get(indicatorId)?.metadata;
  }

  listAll(): IndicatorMetadata[] {
    return Array.from(this.indicators.values()).map((entry) => entry.metadata);
  }

  listByCategory(category: string): IndicatorMetadata[] {
    return this.listAll().filter((m) => m.category === category);
  }

  has(indicatorId: string): boolean {
    return this.indicators.has(indicatorId);
  }
}

/** Create a new empty indicator registry. */
export function createIndicatorRegistry(): IndicatorRegistry {
  return new IndicatorRegistryImpl();
}

function p(key: string, label: string, type: IndicatorParamType, defaultValue: number | string | boolean, opts?: { min?: number; max?: number; step?: number; options?: string[] }): { key: string; label: string; type: IndicatorParamType; defaultValue: number | string | boolean; min?: number; max?: number; step?: number; options?: string[] } {
  return { key, label, type, defaultValue, ...opts };
}

function srcParam(): { key: string; label: string; type: IndicatorParamType; defaultValue: string; options: string[] } {
  return { key: "source", label: "Source", type: ParamType.Source, defaultValue: "close", options: ["close", "open", "high", "low", "hl2", "hlc3", "ohlc4"] };
}

function periodParam(defaultValue: number = 14): { key: string; label: string; type: IndicatorParamType; defaultValue: number; min: number; max: number; step: number } {
  return { key: "period", label: "Period", type: ParamType.Integer, defaultValue, min: 1, max: 500, step: 1 };
}

