import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Parabolic SAR — Stop and Reverse. */
export function sar(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const accelStart = (params["accelStart"] as number | undefined) ?? 0.02;
  const accelStep = (params["accelStep"] as number | undefined) ?? 0.02;
  const accelMax = (params["accelMax"] as number | undefined) ?? 0.2;

  const len = data.length;
  const result = fillNaN(len);

  if (len < 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("sar", timestamps, [result]);
  }

  let isLong = data[1]!.close > data[0]!.close;
  let af = accelStart;
  let ep = isLong ? data[0]!.high : data[0]!.low;
  let sarValue = isLong ? data[0]!.low : data[0]!.high;

  result[0] = sarValue;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const prevBar = data[i - 1]!;

    sarValue = sarValue + af * (ep - sarValue);

    if (isLong) {
      sarValue = Math.min(sarValue, prevBar.low, i >= 2 ? data[i - 2]!.low : prevBar.low);

      if (bar.low < sarValue) {
        isLong = false;
        sarValue = ep;
        ep = bar.low;
        af = accelStart;
      } else {
        if (bar.high > ep) {
          ep = bar.high;
          af = Math.min(af + accelStep, accelMax);
        }
      }
    } else {
      sarValue = Math.max(sarValue, prevBar.high, i >= 2 ? data[i - 2]!.high : prevBar.high);

      if (bar.high > sarValue) {
        isLong = true;
        sarValue = ep;
        ep = bar.high;
        af = accelStart;
      } else {
        if (bar.low < ep) {
          ep = bar.low;
          af = Math.min(af + accelStep, accelMax);
        }
      }
    }

    result[i] = sarValue;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("sar", timestamps, [result]);
}
