import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput } from "../utils";

/** Accumulation/Distribution Line. */
export function ad(
  data: OHLCV[],
  _params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const len = data.length;
  const result = new Array<number>(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("ad", timestamps, [result]);
  }

  let cumulative = 0;

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const range = bar.high - bar.low;
    const mfMultiplier = range === 0 ? 0 : ((bar.close - bar.low) - (bar.high - bar.close)) / range;
    cumulative += mfMultiplier * bar.volume;
    result[i] = cumulative;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("ad", timestamps, [result]);
}
