import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, emaArray } from "../utils";

/**
 * Long/Short Ratio Indicator — estimates long vs short positioning
 * from candlestick structure (close position within H-L range).
 */
export function longShortRatioIndicator(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;

  const len = data.length;
  const rawRatio = new Array<number>(len);

  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const range = bar.high - bar.low;
    if (range === 0) {
      rawRatio[i] = 1;
    } else {
      const longPressure = (bar.close - bar.low) / range;
      const shortPressure = (bar.high - bar.close) / range;
      rawRatio[i] = shortPressure === 0 ? 10 : longPressure / shortPressure;
    }
  }

  const smoothed = emaArray(rawRatio, period);
  const timestamps = extractTimestamps(data);
  return buildOutput("long-short-ratio-indicator", timestamps, [smoothed]);
}
