import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Connors RSI — combines RSI, streak RSI, and percentile rank. */
export function crsi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const rsiPeriod = (params["rsiPeriod"] as number | undefined) ?? 3;
  const streakPeriod = (params["streakPeriod"] as number | undefined) ?? 2;
  const rankPeriod = (params["rankPeriod"] as number | undefined) ?? 100;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  if (len < Math.max(rsiPeriod, streakPeriod, rankPeriod) + 2) {
    const timestamps = extractTimestamps(data);
    return buildOutput("crsi", timestamps, [result]);
  }

  const computeRsi = (values: number[], period: number): number[] => {
    const r = fillNaN(values.length);
    if (values.length < period + 1) return r;
    let ag = 0, al = 0;
    for (let i = 1; i <= period; i++) {
      const ch = values[i]! - values[i - 1]!;
      if (ch > 0) ag += ch; else al += Math.abs(ch);
    }
    ag /= period;
    al /= period;
    r[period] = al === 0 ? 100 : 100 - 100 / (1 + ag / al);
    for (let i = period + 1; i < values.length; i++) {
      const ch = values[i]! - values[i - 1]!;
      ag = (ag * (period - 1) + (ch > 0 ? ch : 0)) / period;
      al = (al * (period - 1) + (ch < 0 ? Math.abs(ch) : 0)) / period;
      r[i] = al === 0 ? 100 : 100 - 100 / (1 + ag / al);
    }
    return r;
  };

  const priceRsi = computeRsi(src, rsiPeriod);

  const streak = new Array<number>(len);
  streak[0] = 0;
  for (let i = 1; i < len; i++) {
    if (src[i]! > src[i - 1]!) {
      streak[i] = streak[i - 1]! > 0 ? streak[i - 1]! + 1 : 1;
    } else if (src[i]! < src[i - 1]!) {
      streak[i] = streak[i - 1]! < 0 ? streak[i - 1]! - 1 : -1;
    } else {
      streak[i] = 0;
    }
  }

  const streakRsi = computeRsi(streak, streakPeriod);

  const roc1 = fillNaN(len);
  for (let i = 1; i < len; i++) {
    roc1[i] = src[i]! - src[i - 1]!;
  }

  const pctRank = fillNaN(len);
  for (let i = rankPeriod; i < len; i++) {
    const current = roc1[i]!;
    if (Number.isNaN(current)) continue;
    let count = 0;
    for (let j = i - rankPeriod; j < i; j++) {
      if (!Number.isNaN(roc1[j]!) && roc1[j]! < current) count++;
    }
    pctRank[i] = (count / rankPeriod) * 100;
  }

  for (let i = 0; i < len; i++) {
    if (!Number.isNaN(priceRsi[i]!) && !Number.isNaN(streakRsi[i]!) && !Number.isNaN(pctRank[i]!)) {
      result[i] = (priceRsi[i]! + streakRsi[i]! + pctRank[i]!) / 3;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("crsi", timestamps, [result]);
}
