import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";
import { computeVolumeProfile } from "./volume-profile";

/**
 * Volume Profile indicator function wrapper.
 *
 * Returns the volume at each bar's mid-price row (similar to VPFR),
 * but the real rendering is handled by VolumeProfileOverlayRenderer.
 * This wrapper exists to allow the indicator registry to list Volume Profile
 * and to provide status-line values.
 */
export function volumeProfileIndicator(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const rows = (params["rows"] as number | undefined) ?? 24;
  const len = data.length;

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("volume-profile", timestamps, [fillNaN(len)]);
  }

  const profile = computeVolumeProfile(data, { rows });

  // Map each bar to its corresponding row's volume
  const result = new Array<number>(len);
  const rowHeight = profile.rowHeight;

  if (rowHeight <= 0 || profile.rows.length === 0) {
    for (let i = 0; i < len; i++) {
      result[i] = data[i]!.volume;
    }
  } else {
    const overallLow = profile.rows[0]!.priceLevel - rowHeight / 2;
    const numRows = profile.rows.length;

    for (let i = 0; i < len; i++) {
      const bar = data[i]!;
      const midPrice = (bar.high + bar.low) / 2;
      const rowIdx = Math.min(
        numRows - 1,
        Math.max(0, Math.floor((midPrice - overallLow) / rowHeight)),
      );
      result[i] = profile.rows[rowIdx]!.totalVolume;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("volume-profile", timestamps, [result]);
}
