import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN, wilderSmooth } from "../utils";

/** Williams Alligator — three smoothed moving averages with offset. */
export function alligator(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const jawPeriod = (params["jawPeriod"] as number | undefined) ?? 13;
  const jawOffset = (params["jawOffset"] as number | undefined) ?? 8;
  const teethPeriod = (params["teethPeriod"] as number | undefined) ?? 8;
  const teethOffset = (params["teethOffset"] as number | undefined) ?? 5;
  const lipsPeriod = (params["lipsPeriod"] as number | undefined) ?? 5;
  const lipsOffset = (params["lipsOffset"] as number | undefined) ?? 3;

  const len = data.length;
  const hl2 = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    hl2[i] = (data[i]!.high + data[i]!.low) / 2;
  }

  const jawRaw = wilderSmooth(hl2, jawPeriod);
  const teethRaw = wilderSmooth(hl2, teethPeriod);
  const lipsRaw = wilderSmooth(hl2, lipsPeriod);

  const jaw = fillNaN(len);
  const teeth = fillNaN(len);
  const lips = fillNaN(len);

  for (let i = 0; i < len; i++) {
    if (i + jawOffset < len && !Number.isNaN(jawRaw[i]!)) {
      jaw[i + jawOffset] = jawRaw[i]!;
    }
    if (i + teethOffset < len && !Number.isNaN(teethRaw[i]!)) {
      teeth[i + teethOffset] = teethRaw[i]!;
    }
    if (i + lipsOffset < len && !Number.isNaN(lipsRaw[i]!)) {
      lips[i + lipsOffset] = lipsRaw[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("alligator", timestamps, [jaw, teeth, lips]);
}
