import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { adx } from "./adx";

/** Directional Movement Index — alias for ADX (includes +DI and -DI). */
export function dmi(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = adx(data, params);
  return { indicatorId: "dmi", data: result.data };
}
