import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { smaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Relative Volume — current volume relative to average. */
export function relativeVolume(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 20;
  const len = data.length;

  const volumes = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    volumes[i] = data[i]!.volume;
  }

  const avgVol = smaArray(volumes, period);
  const result = fillNaN(len);

  for (let i = period - 1; i < len; i++) {
    if (!Number.isNaN(avgVol[i]!) && avgVol[i]! !== 0) {
      result[i] = volumes[i]! / avgVol[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("relative-volume", timestamps, [result]);
}
