import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { emaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Mass Index — identifies trend reversals using range expansion/contraction. */
export function massIndex(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const emaPeriod = (params["emaPeriod"] as number | undefined) ?? 9;
  const sumPeriod = (params["sumPeriod"] as number | undefined) ?? 25;

  const len = data.length;
  const hlDiff = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    hlDiff[i] = data[i]!.high - data[i]!.low;
  }

  const ema1 = emaArray(hlDiff, emaPeriod);
  const validEma1 = ema1.filter((v) => !Number.isNaN(v));
  const ema2 = emaArray(validEma1, emaPeriod);

  const emaRatio = fillNaN(len);
  const offset = (emaPeriod - 1) * 2;

  for (let i = 0; i < ema2.length; i++) {
    const idx = offset + i;
    if (idx < len && !Number.isNaN(ema2[i]!) && ema2[i]! !== 0 && !Number.isNaN(ema1[idx]!)) {
      emaRatio[idx] = ema1[idx]! / ema2[i]!;
    }
  }

  const result = fillNaN(len);
  for (let i = offset + sumPeriod - 1; i < len; i++) {
    let sum = 0;
    let valid = true;
    for (let j = i - sumPeriod + 1; j <= i; j++) {
      if (Number.isNaN(emaRatio[j]!)) { valid = false; break; }
      sum += emaRatio[j]!;
    }
    if (valid) result[i] = sum;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("mass-index", timestamps, [result]);
}
