import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN } from "../utils";

export function kama(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 10;
  const fastPeriod = (params["fastPeriod"] as number | undefined) ?? 2;
  const slowPeriod = (params["slowPeriod"] as number | undefined) ?? 30;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("kama", timestamps, [result]);
  }

  const fastSC = 2 / (fastPeriod + 1);
  const slowSC = 2 / (slowPeriod + 1);

  result[period - 1] = src[period - 1]!;

  for (let i = period; i < len; i++) {
    const direction = Math.abs(src[i]! - src[i - period]!);
    let volatility = 0;
    for (let j = i - period + 1; j <= i; j++) {
      volatility += Math.abs(src[j]! - src[j - 1]!);
    }

    const er = volatility === 0 ? 0 : direction / volatility;
    const sc = (er * (fastSC - slowSC) + slowSC);
    const smoothingConstant = sc * sc;

    result[i] = result[i - 1]! + smoothingConstant * (src[i]! - result[i - 1]!);
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("kama", timestamps, [result]);
}
