import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, wmaArray, extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Coppock Curve — long-term momentum oscillator. */
export function coppock(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const longRoc = (params["longRoc"] as number | undefined) ?? 14;
  const shortRoc = (params["shortRoc"] as number | undefined) ?? 11;
  const wmaPeriod = (params["wmaPeriod"] as number | undefined) ?? 10;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const maxRoc = Math.max(longRoc, shortRoc);

  if (len < maxRoc + 1) {
    const timestamps = extractTimestamps(data);
    return buildOutput("coppock", timestamps, [fillNaN(len)]);
  }

  const rocSum = fillNaN(len);
  for (let i = maxRoc; i < len; i++) {
    const lr = src[i - longRoc]! === 0 ? 0 : ((src[i]! - src[i - longRoc]!) / src[i - longRoc]!) * 100;
    const sr = src[i - shortRoc]! === 0 ? 0 : ((src[i]! - src[i - shortRoc]!) / src[i - shortRoc]!) * 100;
    rocSum[i] = lr + sr;
  }

  const validRocSum = rocSum.filter((v) => !Number.isNaN(v));
  const coppockValues = wmaArray(validRocSum, wmaPeriod);

  const result = fillNaN(len);
  const startIdx = maxRoc + wmaPeriod - 1;

  for (let i = 0; i < coppockValues.length; i++) {
    const idx = startIdx + i;
    if (idx < len && !Number.isNaN(coppockValues[i]!)) {
      result[idx] = coppockValues[i]!;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("coppock", timestamps, [result]);
}
