import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractSource, extractTimestamps, buildOutput, fillNaN, stdDev, smaArray } from "../utils";

/** VIDYA — Variable Index Dynamic Average using Chande Momentum Oscillator. */
export function vidya(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const smoothing = (params["smoothing"] as number | undefined) ?? 9;
  const source = (params["source"] as string | undefined) ?? "close";

  const src = extractSource(data, source);
  const len = src.length;
  const result = fillNaN(len);

  if (len < period) {
    const timestamps = extractTimestamps(data);
    return buildOutput("vidya", timestamps, [result]);
  }

  const sc = 2 / (smoothing + 1);

  result[period - 1] = src[period - 1]!;

  for (let i = period; i < len; i++) {
    let gainSum = 0;
    let lossSum = 0;
    for (let j = i - period + 1; j <= i; j++) {
      const change = src[j]! - src[j - 1]!;
      if (change > 0) gainSum += change;
      else lossSum += Math.abs(change);
    }
    const totalChange = gainSum + lossSum;
    const cmo = totalChange === 0 ? 0 : Math.abs((gainSum - lossSum) / totalChange);

    result[i] = result[i - 1]! + sc * cmo * (src[i]! - result[i - 1]!);
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("vidya", timestamps, [result]);
}
