import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, emaArray } from "../utils";

/** A single real open interest data point from the OpenInterestService. */
export interface OIRealDataPoint {
  readonly timestamp: number;
  readonly value: number;
}

/**
 * Open Interest Indicator.
 *
 * When `realData` is supplied via params, the indicator maps real exchange
 * OI values directly (with optional EMA smoothing controlled by `period`).
 *
 * When `realData` is absent, it falls back to a volume-accumulation proxy
 * that estimates OI direction from price and volume. The registry
 * description distinguishes the two modes.
 */
export function openInterestIndicator(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 14;
  const realData = params["realData"] as unknown as OIRealDataPoint[] | undefined;

  if (realData && realData.length > 0) {
    return computeFromRealData(data, realData, period);
  }

  return computeVolumeProxy(data, period);
}

/**
 * Map real OI data points onto the OHLCV timestamp grid. For each candle,
 * find the closest OI reading whose timestamp is <= the candle timestamp.
 * Apply optional EMA smoothing when period > 1.
 */
function computeFromRealData(
  data: OHLCV[],
  realData: OIRealDataPoint[],
  period: number,
): IndicatorOutput {
  const len = data.length;
  const oiValues = new Array<number>(len);

  // realData is expected to be sorted by timestamp ascending
  let rdIdx = 0;
  let lastOI = realData[0]!.value;

  for (let i = 0; i < len; i++) {
    const candleTs = data[i]!.timestamp;
    // Advance through realData to find the latest point at or before this candle
    while (rdIdx < realData.length - 1 && realData[rdIdx + 1]!.timestamp <= candleTs) {
      rdIdx++;
    }
    if (realData[rdIdx]!.timestamp <= candleTs) {
      lastOI = realData[rdIdx]!.value;
    }
    oiValues[i] = lastOI;
  }

  const output = period > 1 ? emaArray(oiValues, period) : oiValues;
  const timestamps = extractTimestamps(data);
  return buildOutput("open-interest-indicator", timestamps, [output]);
}

/**
 * Volume-accumulation proxy for open interest when real data is unavailable.
 * Accumulates signed volume (positive on bullish bars, negative on bearish)
 * and applies EMA smoothing.
 */
function computeVolumeProxy(data: OHLCV[], period: number): IndicatorOutput {
  const len = data.length;
  const oiProxy = new Array<number>(len);

  if (len === 0) {
    const timestamps = extractTimestamps(data);
    return buildOutput("open-interest-indicator", timestamps, [oiProxy]);
  }

  let cumOI = 0;
  for (let i = 0; i < len; i++) {
    const bar = data[i]!;
    const direction = bar.close >= bar.open ? 1 : -1;
    cumOI += bar.volume * direction;
    oiProxy[i] = Math.abs(cumOI);
  }

  const smoothed = emaArray(oiProxy, period);
  const timestamps = extractTimestamps(data);
  return buildOutput("open-interest-indicator", timestamps, [smoothed]);
}
