import type { OHLCV } from "@deskmodal/core";

/**
 * Sanitize a numeric value, replacing NaN or Infinity with a fallback.
 * Used at indicator input boundaries to prevent corruption propagation.
 */
function sanitizeValue(value: number, fallback: number): number {
  if (Number.isFinite(value)) {
    return value;
  }
  return fallback;
}

/**
 * Sanitize an array of numeric values in place.
 * Replaces NaN/Infinity with the previous valid value (or 0 if none).
 * Returns the same array (mutated) for zero-allocation usage.
 */
export function sanitizeArray(values: number[]): number[] {
  let lastValid = 0;
  for (let i = 0; i < values.length; i++) {
    const v = values[i]!;
    if (Number.isFinite(v)) {
      lastValid = v;
    } else {
      values[i] = lastValid;
    }
  }
  return values;
}

/**
 * Extract a price source series from OHLCV data.
 * Supports: close, open, high, low, hl2, hlc3, ohlc4, volume.
 *
 * Sanitizes output: NaN/Infinity values are replaced with the previous
 * valid value to prevent corruption propagation through indicator chains.
 */
export function extractSource(data: OHLCV[], source: string): number[] {
  const len = data.length;
  const result = new Array<number>(len);

  switch (source) {
    case "open":
      for (let i = 0; i < len; i++) result[i] = data[i]!.open;
      break;
    case "high":
      for (let i = 0; i < len; i++) result[i] = data[i]!.high;
      break;
    case "low":
      for (let i = 0; i < len; i++) result[i] = data[i]!.low;
      break;
    case "hl2":
      for (let i = 0; i < len; i++) {
        const bar = data[i]!;
        result[i] = (bar.high + bar.low) / 2;
      }
      break;
    case "hlc3":
      for (let i = 0; i < len; i++) {
        const bar = data[i]!;
        result[i] = (bar.high + bar.low + bar.close) / 3;
      }
      break;
    case "ohlc4":
      for (let i = 0; i < len; i++) {
        const bar = data[i]!;
        result[i] = (bar.open + bar.high + bar.low + bar.close) / 4;
      }
      break;
    case "volume":
      for (let i = 0; i < len; i++) result[i] = data[i]!.volume;
      break;
    default:
      for (let i = 0; i < len; i++) result[i] = data[i]!.close;
      break;
  }

  return sanitizeArray(result);
}

/** Compute a rolling sum over a fixed window. First (period-1) values are NaN. */
export function rollingSum(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len < period || period < 1) return result;

  let sum = 0;
  for (let i = 0; i < period; i++) {
    sum += values[i]!;
  }
  result[period - 1] = sum;

  for (let i = period; i < len; i++) {
    sum += values[i]! - values[i - period]!;
    result[i] = sum;
  }

  return result;
}

/**
 * Compute a rolling maximum over a fixed window. First (period-1) values are NaN.
 * Uses a monotonic deque for O(n) total complexity instead of O(n*period).
 */
export function rollingMax(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len < period || period < 1) return result;

  // Monotonic deque stores indices; front is always the index of the max value
  const deque: number[] = [];

  for (let i = 0; i < len; i++) {
    // Remove elements from the back that are smaller than current
    while (deque.length > 0 && values[deque[deque.length - 1]!]! <= values[i]!) {
      deque.pop();
    }
    deque.push(i);

    // Remove elements from front that are outside the window
    while (deque[0]! < i - period + 1) {
      deque.shift();
    }

    if (i >= period - 1) {
      result[i] = values[deque[0]!]!;
    }
  }

  return result;
}

/**
 * Compute a rolling minimum over a fixed window. First (period-1) values are NaN.
 * Uses a monotonic deque for O(n) total complexity instead of O(n*period).
 */
export function rollingMin(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len < period || period < 1) return result;

  // Monotonic deque stores indices; front is always the index of the min value
  const deque: number[] = [];

  for (let i = 0; i < len; i++) {
    // Remove elements from the back that are larger than current
    while (deque.length > 0 && values[deque[deque.length - 1]!]! >= values[i]!) {
      deque.pop();
    }
    deque.push(i);

    // Remove elements from front that are outside the window
    while (deque[0]! < i - period + 1) {
      deque.shift();
    }

    if (i >= period - 1) {
      result[i] = values[deque[0]!]!;
    }
  }

  return result;
}

/** Compute a Simple Moving Average. First (period-1) values are NaN. */
export function smaArray(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len < period || period < 1) return result;

  let sum = 0;
  for (let i = 0; i < period; i++) {
    sum += values[i]!;
  }
  result[period - 1] = sum / period;

  for (let i = period; i < len; i++) {
    sum += values[i]! - values[i - period]!;
    result[i] = sum / period;
  }

  return result;
}

/** Compute an Exponential Moving Average. */
export function emaArray(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len < period || period < 1) return result;

  const k = 2 / (period + 1);

  let sum = 0;
  for (let i = 0; i < period; i++) {
    sum += values[i]!;
  }
  result[period - 1] = sum / period;

  for (let i = period; i < len; i++) {
    result[i] = values[i]! * k + result[i - 1]! * (1 - k);
  }

  return result;
}

/** Compute True Range for OHLCV data. First value uses H-L, subsequent include prev close. */
export function trueRange(data: OHLCV[]): number[] {
  const len = data.length;
  if (len === 0) return [];

  const result = new Array<number>(len);
  result[0] = data[0]!.high - data[0]!.low;

  for (let i = 1; i < len; i++) {
    const bar = data[i]!;
    const prevClose = data[i - 1]!.close;
    const hl = bar.high - bar.low;
    const hc = Math.abs(bar.high - prevClose);
    const lc = Math.abs(bar.low - prevClose);
    result[i] = Math.max(hl, hc, lc);
  }

  return result;
}

/** Return true where series a crosses above series b. */
export function crossOver(a: number[], b: number[]): boolean[] {
  const len = Math.min(a.length, b.length);
  const result = new Array<boolean>(len);

  result[0] = false;

  for (let i = 1; i < len; i++) {
    result[i] = a[i - 1]! <= b[i - 1]! && a[i]! > b[i]!;
  }

  return result;
}

/** Return true where series a crosses below series b. */
export function crossUnder(a: number[], b: number[]): boolean[] {
  const len = Math.min(a.length, b.length);
  const result = new Array<boolean>(len);

  result[0] = false;

  for (let i = 1; i < len; i++) {
    result[i] = a[i - 1]! >= b[i - 1]! && a[i]! < b[i]!;
  }

  return result;
}

/** Wilder's smoothing (SMMA / RMA). Equivalent to EMA with k = 1/period. */
export function wilderSmooth(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len < period || period < 1) return result;

  let sum = 0;
  for (let i = 0; i < period; i++) {
    sum += values[i]!;
  }
  result[period - 1] = sum / period;

  const k = 1 / period;
  for (let i = period; i < len; i++) {
    result[i] = values[i]! * k + result[i - 1]! * (1 - k);
  }

  return result;
}

/** Return an array of the given length, filled with NaN. */
export function fillNaN(length: number): number[] {
  const result = new Array<number>(length);
  for (let i = 0; i < length; i++) {
    result[i] = NaN;
  }
  return result;
}

/** Compute a Weighted Moving Average. First (period-1) values are NaN. */
export function wmaArray(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len < period || period < 1) return result;

  const denominator = (period * (period + 1)) / 2;

  for (let i = period - 1; i < len; i++) {
    let sum = 0;
    for (let j = 0; j < period; j++) {
      sum += values[i - period + 1 + j]! * (j + 1);
    }
    result[i] = sum / denominator;
  }

  return result;
}

/**
 * Standard deviation of a rolling window.
 * First (period-1) values are NaN.
 */
export function stdDev(values: number[], period: number): number[] {
  const len = values.length;
  const result = fillNaN(len);

  if (len < period || period < 1) return result;

  const means = smaArray(values, period);

  for (let i = period - 1; i < len; i++) {
    const mean = means[i]!;
    let sumSqDiff = 0;
    for (let j = i - period + 1; j <= i; j++) {
      const diff = values[j]! - mean;
      sumSqDiff += diff * diff;
    }
    result[i] = Math.sqrt(sumSqDiff / period);
  }

  return result;
}

/**
 * Convert an array of numbers to Float64Array.
 * Handles NaN values by keeping them as NaN in the result.
 */
export function toFloat64(values: number[]): Float64Array {
  const arr = new Float64Array(values.length);
  for (let i = 0; i < values.length; i++) {
    arr[i] = values[i]!;
  }
  return arr;
}

/**
 * Build IndicatorOutput from computed arrays and metadata.
 * Converts number arrays to IndicatorOutputValue format.
 */
export function buildOutput(
  indicatorId: string,
  timestamps: number[],
  series: number[][],
): { indicatorId: string; data: Array<{ timestamp: number; values: (number | null)[]; colorHints?: (string | null)[] }> } {
  const len = timestamps.length;
  const data: Array<{ timestamp: number; values: (number | null)[]; colorHints?: (string | null)[] }> = new Array(len);

  for (let i = 0; i < len; i++) {
    const values: (number | null)[] = new Array(series.length);
    for (let j = 0; j < series.length; j++) {
      const v = series[j]![i]!;
      values[j] = Number.isNaN(v) ? null : v;
    }
    data[i] = { timestamp: timestamps[i]!, values };
  }

  return { indicatorId, data };
}

/** Extract timestamps from OHLCV array. */
export function extractTimestamps(data: OHLCV[]): number[] {
  const len = data.length;
  const result = new Array<number>(len);
  for (let i = 0; i < len; i++) {
    result[i] = data[i]!.timestamp;
  }
  return result;
}
