import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN, stdDev as computeStdDev, emaArray } from "../utils";

/** Relative Volatility Index — directional volatility measure using std dev. */
export function rviVol(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 10;
  const smoothPeriod = (params["smoothPeriod"] as number | undefined) ?? 14;

  const len = data.length;
  const closes = new Array<number>(len);
  for (let i = 0; i < len; i++) closes[i] = data[i]!.close;

  const sd = computeStdDev(closes, period);

  const upSD = fillNaN(len);
  const downSD = fillNaN(len);

  for (let i = 1; i < len; i++) {
    if (Number.isNaN(sd[i]!)) continue;
    if (closes[i]! > closes[i - 1]!) {
      upSD[i] = sd[i]!;
      downSD[i] = 0;
    } else {
      upSD[i] = 0;
      downSD[i] = sd[i]!;
    }
  }

  const validUp = upSD.filter((v) => !Number.isNaN(v));
  const validDown = downSD.filter((v) => !Number.isNaN(v));
  const emaUp = emaArray(validUp, smoothPeriod);
  const emaDown = emaArray(validDown, smoothPeriod);

  const result = fillNaN(len);
  const offset = period;

  for (let i = 0; i < emaUp.length; i++) {
    const idx = offset + i;
    if (idx < len && !Number.isNaN(emaUp[i]!) && !Number.isNaN(emaDown[i]!)) {
      const total = emaUp[i]! + emaDown[i]!;
      result[idx] = total === 0 ? 50 : (emaUp[i]! / total) * 100;
    }
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("rvi-vol", timestamps, [result]);
}
