import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { extractTimestamps, buildOutput, fillNaN } from "../utils";

/** Fractal — Williams' fractal: 5-bar patterns marking swing highs and lows. */
export function fractal(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const period = (params["period"] as number | undefined) ?? 2;
  const len = data.length;

  const upFractal = fillNaN(len);
  const downFractal = fillNaN(len);

  for (let i = period; i < len - period; i++) {
    let isUp = true;
    let isDown = true;

    for (let j = 1; j <= period; j++) {
      if (data[i]!.high <= data[i - j]!.high) isUp = false;
      if (data[i]!.high <= data[i + j]!.high) isUp = false;
      if (data[i]!.low >= data[i - j]!.low) isDown = false;
      if (data[i]!.low >= data[i + j]!.low) isDown = false;
    }

    if (isUp) upFractal[i] = data[i]!.high;
    if (isDown) downFractal[i] = data[i]!.low;
  }

  const timestamps = extractTimestamps(data);
  return buildOutput("fractal", timestamps, [upFractal, downFractal]);
}
