import type { OHLCV, IndicatorOutput } from "@deskmodal/core";
import { kst } from "../oscillators/kst";

/** Know Sure Thing — alias for KST. */
export function knowSureThing(
  data: OHLCV[],
  params: Record<string, number | string | boolean>,
): IndicatorOutput {
  const result = kst(data, params);
  return { indicatorId: "know-sure-thing", data: result.data };
}
